return ['domain'=>'agnosis','plural-forms'=>'nplurals=2; plural=n != 1;','language'=>'ca','project-id-version'=>'Agnosis 0.9.21','pot-creation-date'=>'2026-07-13T22:58+00:00','po-revision-date'=>'2026-07-12 17:24+0000','x-generator'=>'Loco https://localise.biz/','messages'=>['Agnosis'=>'Agnosis','https://agnosis.art'=>'https://agnosis.art','Art blooming out of oblivion. Email your art, AI polishes it, the world sees it. A free, federated publishing network for independent artists.'=>'Art que floreix de l’oblit. Envia la teva obra per correu electrònic, la IA la polimenta i el món la veu. Una xarxa de publicació federada i gratuïta per a artistes independents.','Agnosis requires PHP %s or higher.'=>'Agnosis requereix PHP %s o superior.','Agnosis requires WordPress %s or higher.'=>'Agnosis requereix WordPress %s o superior.','Filter by medium'=>'Filtra per mitjà','All'=>'Tots','Enlarged image'=>'Imatge ampliada','Featured'=>'Destacat','Enlarge'=>'Amplia','Gallery pages'=>'Pàgines de la galeria','Prev'=>'Anterior','Next'=>'Següent','Contact Messages'=>'Missatges de contacte','No contact messages yet.'=>'Encara no hi ha cap missatge de contacte.','No messages match this filter.'=>'No hi ha cap missatge que coincideixi amb aquest filtre.','#'=>'#','Artist'=>'Artista','From'=>'De','Message'=>'Missatge','Status'=>'Estat','Received'=>'Rebut','Actions'=>'Accions','(deleted artist #%d)'=>'(artista suprimit #%d)','You do not have permission to perform this action.'=>'No teniu permís per dur a terme aquesta acció.','Message deleted.'=>'Missatge suprimit.','All statuses'=>'Tots els estats','Sent'=>'Enviat','Rejected'=>'Rebutjat','Filter'=>'Filtra','Reset'=>'Restableix','Page %1$d of %2$d'=>'Pàgina %1$d de %2$d','Previous'=>'Anterior','Delete this message?'=>'Suprimir aquest missatge?','Delete'=>'Suprimeix','just now'=>'ara mateix','%dm ago'=>'fa %d min','%dh ago'=>'fa %d h','Mail from (workflow)'=>'Mail from (workflow)','Newsletter'=>'Butlletí','Agnosis Inbox'=>'Safata d’entrada d’Agnosis','Inbox'=>'Safata d’entrada','No messages in the queue yet. Click "Poll Inbox" to fetch messages from your IMAP account.'=>'Encara no hi ha cap missatge a la cua. Feu clic a "Comprova la safata d’entrada" per obtenir missatges del vostre compte IMAP.','No queue rows match this filter.'=>'No hi ha cap fila a la cua que coincideixi amb aquest filtre.','Subject'=>'Assumpte','Endpoint'=>'Extrem','Files'=>'Fitxers','Error'=>'Error','unregistered sender'=>'remitent no registrat','Old row — delete and re-poll to preview'=>'Fila antiga — elimina-la i torna a fer el sondatge per previsualitzar','Attachment viewer'=>'Visor de fitxers adjunts','Close'=>'Tanca','Queue row deleted. Poll Inbox to re-fetch the message.'=>'La fila de la cua s\'ha eliminat. Fes un sondatge de la safata d\'entrada per tornar a recuperar el missatge.','Queue #%d sent to pipeline. Check back in a few seconds.'=>'La cua #%d s\'ha enviat al pipeline. Torna-hi d\'aquí a uns segons.','Poll complete. %d new message(s) added to the queue.'=>'S\'ha completat el sondatge. S\'han afegit %d missatge(s) nou(s) a la cua.','Force-reprocess: %1$d row(s) reset, %2$d new message(s) enqueued.'=>'Torneu a processar forçat: %1$d fila(es) restablerta(es), %2$d missatge(s) nou(s) afegit(s) a la cua.','Processed %d pending item(s).'=>'S\'han processat %d element(s) pendents.','Pending'=>'Pendent','Processing'=>'Processant','Published'=>'Publicat','Failed'=>'Ha fallat','Skipped'=>'Omesos','All reasons'=>'Tots els motius','%1$d message from an unregistered sender is hidden from this view. <a href="%2$s">View it</a>.'=>'%1$d missatge d\'un remitent no registrat està amagat d\'aquesta vista. <a href="%2$s">Mostra\'l</a>.' . "\0" . '%1$d missatges de remitents no registrats estan amagats d\'aquesta vista. <a href="%2$s">Mostra\'ls</a>.','Poll Inbox'=>'Sondar la safata d\'entrada','Force Reprocess'=>'Torna a processar forçat','Process All Pending'=>'Processa tots els pendents','Goodbye'=>'Adeu','Community'=>'Comunitat','Bounce'=>'Retorn','Awaiting Review'=>'En espera de revisió','Live'=>'En directe','Processed'=>'Processat','Member Removed'=>'Membre suprimit','Broadcast Sent'=>'Emissió enviada','Bounced (too long)'=>'Rebotat (massa llarg)','Handled'=>'Gestionat','Process'=>'Processa','View Post'=>'Mostra la publicació','Reprocess'=>'Torna a processar','Running…'=>'Executant…','Delete this queue row?'=>'Vols eliminar aquesta fila de la cua?','Configuration'=>'Configuració','Force-reprocess complete. %1$d queue row(s) reset, %2$d new message(s) enqueued. Click "Process Pending Queue" to run the AI pipeline.'=>'Torneu a processar forçat completat. S\'han restablert %1$d fila(es) de la cua, s\'han afegit %2$d missatge(s) nou(s) a la cua. Fes clic a "Processa la cua pendent" per executar el pipeline d\'IA.','Log cleared.'=>'El registre s\'ha esborrat.','Debug files cleared. %d file was removed.'=>'Els fitxers de depuració s\'han esborrat. S\'ha eliminat %d fitxer.' . "\0" . 'Els fitxers de depuració s\'han esborrat. S\'han eliminat %d fitxers.','Term translation cache cleared. Terms will be re-translated the next time they\'re needed.'=>'La memòria cau de traducció de termes s\'ha esborrat. Els termes es tornaran a traduir la pròxima vegada que siguin necessaris.','Processed %d pending queue item(s). Check the Logs tab for details.'=>'S\'han processat %d element(s) de la cua pendents. Consulta la pestanya de registres per als detalls.','Poll complete. %d new message(s) enqueued. Check the Logs tab, then click Process Pending Queue.'=>'S\'ha completat el sondatge. S\'han encolat %d missatge(s) nou(s). Consulta la pestanya de registres i, després, fes clic a Processa la cua pendent.','Applicant admitted. A welcome email has been sent.'=>'Sol·licitant admès. S\'ha enviat un correu electrònic de benvinguda.','Could not admit — the application may no longer be pending.'=>'No s\'ha pogut admetre — és possible que la sol·licitud ja no estigui pendent.','Application rejected.'=>'Sol·licitud rebutjada.','Could not reject — the application may no longer be pending.'=>'No s\'ha pogut rebutjar — és possible que la sol·licitud ja no estigui pendent.','Artist suspended. A notification email has been sent.'=>'Artista suspès. S\'ha enviat un correu electrònic de notificació.','Could not suspend the artist — they may no longer be active.'=>'No s\'ha pogut suspendre l\'artista — és possible que ja no estigui actiu.','Artist permanently deleted. Their account and all content have been removed.'=>'Artista suprimit permanentment. S\'han eliminat el seu compte i tot el contingut.','Could not delete the artist — please try again.'=>'No s\'ha pogut eliminar l\'artista — torna-ho a provar.','Community removal vote opened. All artists have been emailed.'=>'S\'ha obert una votació de retirada de la comunitat. S\'ha enviat un correu electrònic a tots els artistes.','Could not open a removal vote — one may already be active for this artist.'=>'No s\'ha pogut obrir una votació de retirada — potser ja n\'hi ha una d\'activa per a aquest artista.','Issue prepared and queued — it will go out over the next few cron cycles.'=>'La qüestió s’ha preparat i s’ha afegit a la cua — sortirà durant els pròxims cicles de cron.','Could not start this issue — a previous one may still be sending.'=>'No s’ha pogut iniciar aquesta qüestió — potser n’hi ha una de prèvia que encara s’està enviant.','Test email sent — check the inbox you sent it to.'=>'S’ha enviat el correu de prova — comprova la safata d’entrada a la qual l’has enviat.','Could not send the test email — check the address and your site\'s outgoing mail configuration.'=>'No s’ha pogut enviar el correu de prova — comprova l’adreça i la configuració de correu sortint del teu lloc.','Invitation sent.'=>'S’ha enviat la invitació.','Could not send the invitation — check the address and your site\'s outgoing mail configuration.'=>'No s’ha pogut enviar la invitació — comprova l’adreça i la configuració de correu sortint del teu lloc.','Test invitation sent — check the inbox you sent it to.'=>'S’ha enviat la invitació de prova — comprova la safata d’entrada a la qual l’has enviat.','Could not send the test invitation — check the address and your site\'s outgoing mail configuration.'=>'No s’ha pogut enviar la invitació de prova — comprova l’adreça i la configuració de correu sortint del teu lloc.','Test email sent — check whether it lands in your inbox or your spam folder.'=>'S’ha enviat el correu de prova — comprova si arriba a la teva safata d’entrada o a la carpeta de correu brossa.','Failed recipients reset to pending — they will be retried on the next few cron cycles.'=>'Els destinataris fallits s’han restablert a pendent — es reintentaran durant els pròxims cicles de cron.','No failed recipients to retry for this newsletter.'=>'No hi ha destinataris fallits per reintentar per a aquest butlletí.','Art blooming out of oblivion'=>'Art que floreix des de l’oblit','Save Changes'=>'Desa els canvis','Members'=>'Membres','Rules'=>'Regles','General'=>'General','Email Inbox'=>'Safata d’entrada del correu electrònic','AI Providers'=>'Proveïdors d’IA','Behavior'=>'Comportament','Network'=>'Xarxa','Commerce'=>'Comerç','Logs'=>'Registres','— None (inline message only) —'=>'— Cap (només missatge en línia) —','Reset to default'=>'Restableix als valors predeterminats','Replaces the text above with the plugin\'s built-in default — click Save Changes below to keep it.'=>'Substitueix el text de dalt pel valor predeterminat integrat del connector — fes clic a Desa els canvis a continuació per mantenir-lo.','Select Image'=>'Selecciona una imatge','Remove'=>'Elimina','Base domain'=>'Domini base','Root domain for artist subdomains, e.g. agnosis.art. Each artist is reachable at nicename.{base_domain}. Requires a wildcard DNS record (*.{base_domain}) pointing to this server. Leave blank to disable subdomain routing.'=>'Domini arrel per als subdominis dels artistes, per exemple agnosis.art. Cada artista és accessible a nicename.{base_domain}. Requereix un registre DNS comodí (*.{base_domain}) que apunti a aquest servidor. Deixa-ho en blanc per desactivar l’encaminament de subdominis.','Debug logging'=>'Registre de depuració','Writes raw diagnostic dumps of the email intake pipeline (message structure, attachment MIME detection, media conversion, post creation) to a dedicated debug directory — far more detail than the Logs tab keeps, for tracing exactly where a submission was rejected or lost. Turn off once you have what you need; files can accumulate quickly. Can also be forced from wp-config.php with `define( \'AGNOSIS_DEBUG\', true );`, which overrides this toggle. See the Debug Files panel below for the directory location and a clear-files button.'=>'Escriu bolcats de diagnòstic en brut del pipeline d’entrada de correu (estructura del missatge, detecció MIME dels fitxers adjunts, conversió de mèdia, creació de l’entrada) a un directori de depuració dedicat — molt més detall del que conserva la pestanya de Registres, per poder rastrejar exactament on s’ha rebutjat o perdut una tramesa. Desactiva-ho un cop tinguis el que necessites; els fitxers es poden acumular ràpidament. També es pot forçar des de wp-config.php amb `define( \'AGNOSIS_DEBUG\', true );`, que anul·la aquest commutador. Consulta el tauler Fitxers de depuració més avall per veure la ubicació del directori i un botó per esborrar fitxers.','Debug file retention (days)'=>'Retenció dels fitxers de depuració (dies)','Debug dumps older than this are permanently deleted by the daily cleanup — automatically, whether or not debug logging is currently turned on, so files left over from a past debug session don\'t linger indefinitely. A dump is a full raw copy of an artist\'s email, so this defaults shorter than the inbox/queue retention above. Default: 14 days.'=>'Els bolcats de depuració més antics que aquest nombre s’eliminen permanentment amb la neteja diària — automàticament, tant si el registre de depuració està activat com si no, de manera que els fitxers d’una sessió de depuració anterior no es mantinguin indefinidament. Un bolcat és una còpia crua completa del correu d’un artista, així que el valor predeterminat és més curt que la retenció de la safata d’entrada/cua anterior. Valor per defecte: 14 dies.','Email logo'=>'Logotip del correu electrònic','Shown in the header of outgoing HTML emails (submission review, removal confirmation, rejection notice, and both newsletters) in place of the plain "✦ Site Name" text. Leave empty to keep the text wordmark. Displayed at up to 40px tall — any width or aspect ratio works.'=>'Es mostra a la capçalera dels correus HTML sortints (revisió de la tramesa, confirmació d’eliminació, avís de rebuig i tots dos butlletins) en lloc del text pla "✦ Site Name". Deixa-ho buit per mantenir el text de marca. Es mostra amb una alçada de fins a 40 px — qualsevol amplada o proporció funciona.','Preset biography title'=>'Títol de biografia predefinit','When set, every artist\'s biography page uses this exact title instead of their own, regardless of what the artist submitted, edited on their approve form, or later changed on their published page. Leave blank to keep using each artist\'s own title (the default). Shown exactly as typed here on every language version of a biography page — not machine-translated per language. See "Include artist\'s name in preset title" below.'=>'Quan està definit, la pàgina de biografia de cada artista fa servir exactament aquest títol en lloc del seu propi, independentment del que l’artista hagi enviat, hagi editat al formulari d’aprovació o hagi canviat més tard a la seva pàgina publicada. Deixa-ho en blanc per continuar fent servir el títol propi de cada artista (el comportament predeterminat). Es mostra exactament tal com s’ha escrit aquí en cada versió lingüística d’una pàgina de biografia — no es tradueix automàticament per idioma. Consulta "Inclou el nom de l’artista en el títol predefinit" més avall.','Include artist\'s name in preset title'=>'Inclou el nom de l’artista al títol predefinit','When the preset title above is set, append the artist\'s own WordPress display name to it (e.g. "Meet the Artist — Jane Doe"). Has no effect while the preset title is blank.'=>'Quan el títol predefinit anterior està definit, hi afegeix el nom de visualització de WordPress de l’artista (per exemple, "Coneix l’artista — Jane Doe"). No té efecte mentre el títol predefinit sigui buit.','Cloudflare Turnstile site key'=>'Clau del lloc de Cloudflare Turnstile','From your Cloudflare Turnstile widget (dash.cloudflare.com → Turnstile). Adds a human-verification check to the public Subscribe (newsletter-signup) and Join forms. Leave either key blank to leave both forms exactly as they are today.'=>'Del teu giny de Cloudflare Turnstile (dash.cloudflare.com → Turnstile). Afegeix una comprovació de verificació humana als formularis públics de Subscriure’s (newsletter-signup) i Unir-se. Deixa qualsevol de les dues claus en blanc per deixar tots dos formularis exactament com estan ara.','Cloudflare Turnstile secret key'=>'Clau secreta de Cloudflare Turnstile','Kept server-side only — used to verify each form submission directly with Cloudflare before it is accepted.'=>'Es conserva només al costat del servidor — s’utilitza per verificar cada enviament de formulari directament amb Cloudflare abans que s’accepti.','Email driver'=>'Controlador de correu electrònic','Name shown as the sender of admission, vote, welcome, departure, invitation, and submission-review emails. Leave blank to use the site name.'=>'Nom mostrat com a remitent dels correus electrònics d\'admissió, vot, benvinguda, sortida i altres fluxos de treball. Deixa-ho en blanc per utilitzar el nom del lloc.','Mail from: email address'=>'La teva adreça electrònica','Dedicated From: address for admission, vote, welcome, departure, invitation, and submission-review emails — e.g. hello@agnosis.art. This is not one of the endpoint addresses below (submit@, bio@, community@, etc.) — those are where artists send mail in; this is who workflow mail appears to come from. Separate from the Settings → Newsletter sender, which only covers digest mail. Leave blank to use the admin email. Must be a valid, deliverable address on your domain (SPF/DKIM configured) or messages may be marked as spam.'=>'Adreça From: dedicada per als correus electrònics d\'admissió, vot, benvinguda, sortida, invitació i revisió de submissió — per exemple, hello@agnosis.art. Deliberadament separada del remitent de Butlletí → Configuració: aquestes són accions puntuals (un enllaç de vot, un enllaç de revisió), no correu resum. Deixa-ho en blanc per utilitzar el correu electrònic de l\'administrador. Ha de ser una adreça vàlida i lliurable del teu domini (SPF/DKIM configurats) o els missatges poden ser marcats com a correu brossa.','Artwork submissions address'=>'Adreça per a les trameses d’obres','Artists send artwork to this address — e.g. submit@agnosis.art'=>'Els artistes envien les obres a aquesta adreça — per exemple, submit@agnosis.art','Biography submissions address'=>'Adreça per a les trameses de biografia','Artists send biography updates to this address — e.g. bio@agnosis.art'=>'Els artistes envien les actualitzacions de biografia a aquesta adreça — per exemple, bio@agnosis.art','Event submissions address'=>'Adreça per a les trameses d’esdeveniments','Artists send event announcements to this address — e.g. event@agnosis.art'=>'Els artistes envien els anuncis d’esdeveniments a aquesta adreça — per exemple, event@agnosis.art','Replace artwork address'=>'Adreça per substituir obra','Artist sends a new version of an existing artwork. Subject must match the original title. Bypasses duplicate detection — e.g. replace@agnosis.art'=>'L\'artista envia una nova versió d\'una obra existent. L\'assumpte ha de coincidir amb el títol original. Es salta la detecció de duplicats — per exemple, replace@agnosis.art','Removal request address'=>'Adreça per a sol·licituds de retirada','Artist requests takedown of an existing artwork. Subject must match the title. Moves the post to draft pending admin review — e.g. remove@agnosis.art'=>'L\'artista sol·licita la retirada d\'una obra existent. L\'assumpte ha de coincidir amb el títol. Mou la publicació a esborrany pendent de revisió per part de l\'administrador — per exemple, remove@agnosis.art','Promote artwork address'=>'Adreça per promocionar obra','Artist sends an email here (subject = exact artwork title) to choose which artwork represents them in the shared community gallery on the main site — not their own subdomain, which already shows everything they\'ve published. Any previously featured artwork is automatically demoted — e.g. promote@agnosis.art'=>'L\'artista envia un correu aquí (assumpte = títol exacte de l\'obra) per triar quina obra el representa a la galeria comunitària compartida del lloc principal — no al seu subdomini, que ja mostra tot el que ha publicat. Qualsevol obra destacada anteriorment es desmarca automàticament — per exemple, promote@agnosis.art','Photo-only address'=>'Adreça només per a fotos','Opt-out lane for photographers and lens-based artists whose photograph is the artwork, not a snapshot of it. Submissions here are published with the original image exactly as sent — AI enhancement is skipped and the quality-rejection gate is bypassed. AI description (title, tags, alt text) still runs. Use the [Photo] subject indicator as a fallback for mail clients that do not support To: aliases — e.g. photo@agnosis.art'=>'Via de desactivació per a fotògrafs i artistes basats en la lent, la fotografia dels quals és l\'obra, no una captura d\'aquesta. Les trameses aquí es publiquen amb la imatge original exactament tal com s\'ha enviat — la millora amb IA s\'omet i es salta la comprovació de rebuig per qualitat. La descripció amb IA (títol, etiquetes, text alternatiu) continua executant-se. Feu servir l\'indicador d\'assumpte [Photo] com a alternativa per a clients de correu que no admeten àlies a To: — per exemple, photo@agnosis.art','Pure address (no AI at all)'=>'Adreça Pure (sense IA en absolut)','Strictest opt-out lane: nothing sent here is touched by AI — no enhancement, no vision description, no rewriting. The published post title, body, and translated-title subtitle are taken verbatim from the artist\'s own subject and message text; the attached file(s) are published exactly as sent. The quality-rejection gate is bypassed, same as Photo-only. Use the [Pure] subject indicator as a fallback for mail clients that do not support To: aliases — e.g. pure@agnosis.art'=>'Via de desactivació més estricta: res del que s\'envia aquí és tocat per IA — ni millora, ni descripció visual, ni reescriptura. El títol de la publicació, el cos i el subtítol del títol traduït es prenen literalment de l\'assumpte i del text del missatge de l\'artista; els fitxers adjunts es publiquen exactament tal com s\'envien. La comprovació de rebuig per qualitat s\'omet, igual que a Foto només. Feu servir l\'indicador d\'assumpte [Pure] com a alternativa per a clients de correu que no admeten àlies a To: — per exemple, pure@agnosis.art','Goodbye / self-removal address'=>'Adreça de comiat / autoeliminació','Artist emails here (any subject, no attachment needed) to request account deletion. A confirmation link is emailed back before anything is deleted — e.g. goodbye@agnosis.art'=>'L\'artista envia un correu aquí (qualsevol assumpte, no cal cap adjunt) per sol·licitar l\'eliminació del compte. S\'envia per correu un enllaç de confirmació abans d\'eliminar res — per exemple, goodbye@agnosis.art','Community announcement address'=>'Adreça d\'anunci comunitari','Any active artist emails here (any subject, no attachment needed) to send a message to every other community member — e.g. community@agnosis.art. Never processed as a submission and never becomes a post: each recipient gets the subject and message translated into their own language, with the sender\'s name and email included so they can reply directly. Sent from the address configured under Settings → Community → Rules, which can be different from this one. Only works for a message sent by an active, admitted artist.'=>'Qualsevol artista actiu envia un correu aquí (qualsevol assumpte, no cal cap adjunt) per enviar un missatge a la resta de membres de la comunitat — per exemple, community@agnosis.art. Mai es processa com una tramesa ni es converteix en una publicació: cada destinatari rep l\'assumpte i el missatge traduïts al seu idioma, amb el nom i el correu electrònic del remitent inclosos perquè hi puguin respondre directament. S\'envia des de l\'adreça configurada a Configuració → Comunitat → Regles, que pot ser diferent d\'aquesta. Només funciona per a un missatge enviat per un artista actiu i admès.','IMAP host'=>'Amfitrió IMAP','e.g. imap.yourhost.com'=>'p. ex. imap.elvosteuhost.com','IMAP port'=>'Port IMAP','Use SSL'=>'Utilitza SSL','Skip SSL certificate validation'=>'Omet la validació del certificat SSL','⚠ Use only as a temporary workaround when your mail server\'s certificate is not yet trusted (e.g. Plesk self-signed cert before Let\'s Encrypt is applied to the mail daemon). Disable this once the mail server presents a valid certificate.'=>'⚠ Feu-ho servir només com a solució temporal quan el certificat del vostre servidor de correu encara no és de confiança (p. ex. certificat autosignat de Plesk abans que s\'apliqui Let\'s Encrypt al daemon de correu). Desactiveu-ho un cop el servidor de correu presenti un certificat vàlid.','IMAP username'=>'Nom d\'usuari IMAP','Login username for the IMAP account — typically the catch-all mailbox address.'=>'Nom d\'usuari d\'inici de sessió per al compte IMAP — normalment l\'adreça de la bústia catch-all.','Submission email password'=>'Contrasenya del correu de tramesa','Webhook secret'=>'Secret del webhook','HMAC secret shared with your webhook provider (Mailgun, SendGrid…). Used for both the inbound-mail endpoint (/wp-json/agnosis/v1/email/inbound) and the bounce/complaint events endpoint (/wp-json/agnosis/v1/email/events) — point your provider\'s bounce/spam-complaint webhook at the latter to keep your subscriber and artist addresses clean.'=>'Secret HMAC compartit amb el vostre proveïdor de webhooks (Mailgun, SendGrid…). S\'utilitza tant per a l\'extrem de correu entrant (/wp-json/agnosis/v1/email/inbound) com per a l\'extrem d\'esdeveniments de rebots/queixes (/wp-json/agnosis/v1/email/events) — apunteu el webhook de rebots/queixes del vostre proveïdor a aquest últim per mantenir netes les adreces dels subscriptors i dels artistes.','Inbox retention (days)'=>'Retenció de la safata d\'entrada (dies)','IMAP messages and processed/failed queue rows older than this are permanently deleted by the daily cleanup, whether read or unread. Default: 7 days.'=>'IMAP messages and processed/failed queue rows older than this are permanently deleted by the daily cleanup, whether read or unread. Default: 7 days.','Contact message retention (days)'=>'Retenció dels missatges de contacte (dies)','Visitor-to-artist contact messages (sent or rejected) older than this are permanently deleted by the daily cleanup. The visitor\'s IP address is cleared independently after 30 days regardless of this setting, once it\'s no longer useful for abuse investigation. Default: 90 days.'=>'Els missatges de contacte visitant-a-artista (enviats o rebutjats) més antics que això s\'eliminen permanentment durant la neteja diària. L\'adreça IP del visitant s\'esborra independentment al cap de 30 dies, sense importar aquesta configuració, un cop ja no sigui útil per a la investigació d\'abusos. Per defecte: 90 dies.','Per-sender hourly submission limit'=>'Límit horari de trameses per remitent','Maximum submissions accepted from a single artist per hour, across both IMAP and webhook intake. Exceeding this limit silently drops the message (no retry from ESPs). Default: 5.'=>'Nombre màxim de trameses acceptades d\'un sol artista per hora, tant per IMAP com per ingesta per webhook. Superar aquest límit descarta el missatge en silenci (sense reintent per part dels ESP). Per defecte: 5.','Per-artist contact limit'=>'Límit de contacte per artista','Maximum messages the same visitor (by email address) can send to a single artist within the window below — applies across every language version of that artist\'s page. Default: 2.'=>'Nombre màxim de missatges que el mateix visitant (per adreça electrònica) pot enviar a un sol artista dins la finestra següent — s\'aplica a totes les versions lingüístiques de la pàgina d\'aquest artista. Per defecte: 2.','Per-artist contact limit window (hours)'=>'Finestra del límit de contacte per artista (hores)','Time window, in hours, the per-artist contact limit above applies over. Also controls how long a visitor sees the "already contacted" notice instead of the form after messaging an artist. Default: 1 (one hour).'=>'Finestra de temps, en hores, durant la qual s\'aplica el límit de contacte per artista anterior. També controla durant quant temps un visitant veu l\'avís "ja contactat" en lloc del formulari després de contactar amb un artista. Per defecte: 1 (una hora).','Require SPF/DKIM authentication'=>'Requereix autenticació SPF/DKIM','When enabled, intake messages must pass SPF or DKIM authentication (via the Authentication-Results header). Prevents spoofed From: addresses. Requires your ESP to include Authentication-Results headers and your domain to have SPF/DKIM records configured. Leave off if you are not sure — rejected legitimate mail is silent. Default: off.'=>'Quan està activat, els missatges d\'entrada han de superar l\'autenticació SPF o DKIM (mitjançant la capçalera Authentication-Results). Evita adreces From: falsificades. Requereix que el vostre ESP inclogui capçaleres Authentication-Results i que el vostre domini tingui configurats registres SPF/DKIM. Deixeu-ho desactivat si no n\'esteu segur — el correu legítim rebutjat és silenciós. Per defecte: desactivat.','Description provider'=>'Proveïdor de descripció','Analyzes the artwork image and writes the title, body, tags and alt text. WordPress AI Services delegates to whichever provider the site has configured via the AI Services plugin.'=>'Analitza la imatge de l\'obra i escriu el títol, el cos, les etiquetes i el text alternatiu. WordPress AI Services delega en el proveïdor que el lloc tingui configurat mitjançant el connector AI Services.','OpenAI vision model'=>'Model de visió d\'OpenAI','Model used for artwork description when OpenAI is the description provider. Must support vision input.'=>'Model utilitzat per descriure l\'obra quan OpenAI és el proveïdor de descripció. Ha de suportar entrada de visió.','Anthropic model'=>'Model d\'Anthropic','Model used for artwork description when Anthropic is the description provider. Must support vision input.'=>'Model utilitzat per a la descripció de l’obra quan Anthropic és el proveïdor de descripcions. Ha de suportar entrada de visió.','Vision image max width (px)'=>'Amplada màxima de la imatge de visió (px)','Images are downscaled proportionally to this width before being sent to the AI for description — vision token cost scales with resolution, and a description task needs far fewer pixels than the original photo. Applies to artwork photo uploads, rasterised PDF pages, and video poster frames alike. Set to 0 to always send full-resolution images (uses more tokens, no quality difference for typical description tasks). Requires the Imagick PHP extension; images are sent at their original size regardless of this setting when it is unavailable. Default: 800.'=>'Les imatges es redueixen proporcionalment a aquesta amplada abans d’enviar-les a la IA per a la descripció — el cost de tokens de visió escala amb la resolució, i una tasca de descripció necessita molts menys píxels que la foto original. S’aplica igualment a les càrregues de fotos d’obres, pàgines de PDF rasteritzades i fotogrames de pòster de vídeo. Establiu-lo a 0 per enviar sempre imatges a resolució completa (utilitza més tokens, però no hi ha diferència de qualitat en tasques de descripció típiques). Requereix l’extensió PHP Imagick; les imatges s’envien a la seva mida original independentment d’aquesta configuració quan no està disponible. Per defecte: 800.','Enhancement provider'=>'Proveïdor de millora','Auto (OpenAI if key is set)'=>'Automàtic (OpenAI si la clau està definida)','Disabled — use original image'=>'Desactivat — usa la imatge original','Enhances the artwork image before publishing. Uses OpenAI gpt-image-1. Set to Disabled to skip enhancement and publish the original.'=>'Millora la imatge de l’obra abans de publicar-la. Fa servir OpenAI gpt-image-1. Establiu-ho a Desactivat per ometre la millora i publicar l’original.','OpenAI image model'=>'Model d’imatge d’OpenAI','Model used for image enhancement when OpenAI is the enhancement provider.'=>'Model utilitzat per a la millora d\'imatges quan OpenAI és el proveïdor de millora.','Polish biography with AI'=>'Polir la biografia amb IA','When enabled, biography submissions are passed through the AI to fix spelling and make minor text improvements before saving.'=>'Quan està activat, els enviaments de biografia passen per la IA per corregir l\'ortografia i fer petites millores del text abans de desar-los.','Polish events with AI'=>'Polir els esdeveniments amb IA','When enabled, event submissions are passed through the AI to fix spelling and make minor text improvements before saving.'=>'Quan està activat, els enviaments d\'esdeveniments passen per la IA per corregir l\'ortografia i fer petites millores del text abans de desar-los.','Merge biography updates with AI'=>'Combinar les actualitzacions de biografia amb IA','When enabled, biography updates are merged with the existing biography using AI — new information is integrated rather than replacing everything. Recommended: artists can send incremental updates ("I just won an award") without resubmitting their full bio. Disable to always replace the biography with the latest submission.'=>'Quan està activat, les actualitzacions de la biografia es combinen amb la biografia existent mitjançant IA — la informació nova s\'integra en lloc de substituir-ho tot. Recomanat: els artistes poden enviar actualitzacions incrementals ("acabo de guanyar un premi") sense tornar a enviar la biografia completa. Desactiva-ho per substituir sempre la biografia amb l\'últim enviament.','Rejection threshold (quality score)'=>'Llindar de rebuig (puntuació de qualitat)','Photos scoring at or below this value (1–10) are automatically rejected — the artist receives a friendly email explaining the issue and is invited to resubmit. Score 0 disables automatic rejection. Must be lower than the enhancement threshold. Default: 3.'=>'Les fotos que obtinguin aquesta puntuació o una inferior (1–10) es rebutgen automàticament — l\'artista rep un correu electrònic amable que explica el problema i se\'l convida a tornar-ho a enviar. La puntuació 0 desactiva el rebuig automàtic. Ha de ser inferior al llindar de millora. Valor per defecte: 3.','Enhancement threshold (quality score)'=>'Llindar de millora (puntuació de qualitat)','Photos scoring below this value (1–10) are automatically enhanced. Score 10 = perfect photograph, 1 = technically unusable. Default: 7 — only visibly problematic photos are processed. Set to 1 to disable automatic enhancement entirely.'=>'Les fotos que obtinguin una puntuació inferior a aquest valor (1–10) es milloren automàticament. Puntuació 10 = fotografia perfecta, 1 = tècnicament inutilitzable. Valor per defecte: 7 — només es processen les fotos visiblement problemàtiques. Estableix-ho a 1 per desactivar completament la millora automàtica.','OpenAI API key'=>'Clau de l\'API d\'OpenAI','Required when OpenAI is the description or enhancement provider.'=>'Obligatòria quan OpenAI és el proveïdor de descripció o de millora.','Anthropic API key'=>'Clau de l\'API d\'Anthropic','Required when Anthropic is the description provider.'=>'Obligatòria quan Anthropic és el proveïdor de descripció.','Artwork display width (px)'=>'Amplada de visualització de l\'obra (px)','Width of the agnosis-artwork image size used in post content and lightbox. Height scales proportionally. Default: 1920. Existing images need to be regenerated after changing this value.'=>'Amplada de la mida agnosis-artwork utilitzada en el contingut de les publicacions i a la caixa de llum. L\'alçada s\'escalarà proporcionalment. Valor per defecte: 1920. Les imatges existents s\'han de tornar a generar després de canviar aquest valor.','Thumbnail size (px)'=>'Mida de la miniatura (px)','Side length of the square agnosis-thumb size used in submission cards and dashboard. Default: 512. Existing images need to be regenerated after changing this value.'=>'Longitud lateral de la mida quadrada agnosis-thumb utilitzada a les targetes d\'enviament i al tauler. Valor per defecte: 512. Les imatges existents s\'han de tornar a generar després de canviar aquest valor.','Email image width (px)'=>'Amplada de la imatge per al correu electrònic (px)','Width of the agnosis-email size used in artist notification emails. Height scales proportionally — no cropping. Default: 420. Existing images need to be regenerated after changing this value.'=>'Amplada de la mida agnosis-email utilitzada en els correus electrònics de notificació als artistes. L\'alçada s\'escalarà proporcionalment — sense retall. Valor per defecte: 420. Les imatges existents s\'han de tornar a generar després de canviar aquest valor.','Gallery overview — items per page'=>'Resum de la galeria — elements per pàgina','How many artwork cards the gallery overview shows per page. Pool is built proportionally across all artists; featured artworks are preferred. Default: 12.'=>'Quantes targetes d\'obres mostra per pàgina el resum de la galeria. El conjunt es construeix proporcionalment entre tots els artistes; es prioritzen les obres destacades. Valor per defecte: 12.','Review link expiry (days)'=>'Caducitat de l\'enllaç de revisió (dies)','How long the Approve & Publish / Discard links in a submission review email stay valid before an artist has to log in to manage the item instead. Applies uniformly to artwork, biography, and event drafts. Default: 7.'=>'Quant de temps els enllaços Aprova i publica / Descarta d\'un correu electrònic de revisió d\'un enviament continuen sent vàlids abans que l\'artista hagi d\'iniciar sessió per gestionar l\'element. S\'aplica uniformement als esborranys d\'obres, biografies i esdeveniments. Valor per defecte: 7.','System prompt'=>'Indicació del sistema','Sent to the AI as the system instruction. Use {tag_count} and {excerpt_words} as tokens — they are replaced with the values below.'=>'Enviada a la IA com a instrucció del sistema. Utilitza {tag_count} i {excerpt_words} com a tokens — es substitueixen pels valors de més avall.','Artist prompt template'=>'Plantilla de l\'indicació de l\'artista','User message sent alongside the artwork image. Use {artist_prompt} where the artist\'s own description should appear.'=>'Missatge d\'usuari enviat juntament amb la imatge de l\'obra. Utilitza {artist_prompt} allà on hauria d\'aparèixer la descripció pròpia de l\'artista.','Enhancement instructions'=>'Instruccions de millora','Instructions passed to the image enhancement provider. The AI-generated artwork description is appended automatically as context.'=>'Instruccions transmeses al proveïdor de millora d\'imatges. La descripció de l\'obra generada per la IA s\'afegeix automàticament com a context.','Number of tags'=>'Nombre d\'etiquetes','How many tags the AI should generate per artwork. Referenced as {tag_count} in the system prompt.'=>'Quantes etiquetes ha de generar la IA per obra. Es referencia com a {tag_count} a la indicació del sistema.','Excerpt word limit'=>'Límit de paraules de l\'extracte','Maximum words for the one-sentence excerpt. Referenced as {excerpt_words} in the system prompt.'=>'Nombre màxim de paraules per a l\'extracte d\'una sola frase. Es referencia com a {excerpt_words} a la indicació del sistema.','Trust all admitted artists (skip link review entirely)'=>'Confiar en tots els artistes admesos (omet completament la revisió d\'enllaços)','Every artist here was already vouched in by the community — if that trust is enough for you, turn this on to embed any link an artist submits, immediately, with no allowlist check and no AI review at all (the settings below are skipped entirely while this is on). Off by default. Only enable this if you are comfortable that a bad actor who made it through admission could embed a link to anything.'=>'Tots els artistes d\'aquí ja han estat avalats per la comunitat — si aquesta confiança et sembla suficient, activa això per incrustar immediatament qualsevol enllaç que enviï un artista, sense cap comprovació de la llista permesa ni cap revisió per IA (els paràmetres de sota se salten completament mentre això està activat). Desactivat per defecte. Activa-ho només si et sents còmode amb la idea que un actor dolent que hagi passat l\'admissió pugui incrustar un enllaç a qualsevol cosa.','Trusted embed platforms'=>'Plataformes d\'incrustació de confiança','One hostname per line. A submitted link becomes a rich embed immediately if it matches one of these (or a subdomain of one) — no AI review needed, no network request made to the link itself.'=>'Un nom d\'amfitrió per línia. Un enllaç enviat es converteix immediatament en una incrustació rica si coincideix amb un d\'aquests (o amb un subdomini d\'un d\'aquests) — no cal revisió per IA ni es fa cap sol·licitud de xarxa al mateix enllaç.','Let artists submit other links too (AI-reviewed)'=>'Permet que els artistes també enviïn altres enllaços (revisats per IA)','When enabled, a link to a site not on the trusted list above is not simply discarded: the destination page is fetched and reviewed by your configured AI provider (Settings → AI Providers) against the categories below before deciding whether to embed it. If the AI cannot be reached, the request times out, or the page cannot be safely fetched, the link is not embedded — it fails safe. When disabled (the default), only the trusted platforms above are ever embedded.'=>'Quan està activat, un enllaç a un lloc que no sigui a la llista de confiança anterior no es descarta simplement: la pàgina de destinació es descarrega i és revisada pel proveïdor d\'IA configurat (Configuració → Proveïdors d\'IA) segons les categories següents abans de decidir si s\'ha d\'incrustar. Si no es pot contactar amb la IA, la sol·licitud excedeix el temps d\'espera o la pàgina no es pot obtenir amb seguretat, l\'enllaç no s\'incrusta — falla de manera segura. Quan està desactivat (el valor per defecte), només s\'incrusten les plataformes de confiança anteriors.','Block pornographic / sexually explicit content'=>'Bloqueja el contingut pornogràfic / sexualment explícit','Only takes effect when AI review (above) is enabled.'=>'Només té efecte quan la revisió per IA (a dalt) està activada.','Block primarily commercial / promotional sites'=>'Bloqueja els llocs principalment comercials / promocionals','Online stores, advertising, marketing landing pages. Off by default — an artist linking to a shop selling their own prints is common and not inherently unwanted. Only takes effect when AI review (above) is enabled.'=>'Botigues en línia, publicitat, pàgines d\'aterratge de màrqueting. Desactivat per defecte — és habitual que un artista enllaci a una botiga que vengui les seves pròpies impressions i no és inherentment indesitjable. Només té efecte quan la revisió per IA (a dalt) està activada.','Block gambling / betting sites'=>'Bloqueja els llocs de joc / apostes','Additional disallowed categories'=>'Categories addicionals no permeses','Optional — describe any other kind of content the AI should reject, in plain language (e.g. "hate speech or violent extremist content", "phishing or scam pages"). Only takes effect when AI review (above) is enabled.'=>'Opcional — descriu qualsevol altre tipus de contingut que la IA hauria de rebutjar, en llenguatge planer (p. ex. "discurs d\'odi o contingut extremista violent", "pàgines de phishing o d\'estafa"). Només té efecte quan la revisió per IA (a dalt) està activada.','Node label'=>'Etiqueta del node','How this node introduces itself to the network.'=>'Com es presenta aquest node a la xarxa.','Enable ActivityPub federation'=>'Habilita la federació ActivityPub','Broadcast new artworks to Mastodon, Pixelfed and the Fediverse.'=>'Difon les noves obres a Mastodon, Pixelfed i el Fediverse.','Node public key'=>'Clau pública del node','Auto-generated RSA public key for this node. Share this with peer nodes.'=>'Clau pública RSA generada automàticament per a aquest node. Comparteix-la amb nodes companys.','Self-removal (goodbye) requests per sender per day'=>'Sol·licituds d\'autodetirada (adeu) per remitent i dia','Maximum number of self-removal ("goodbye") confirmation emails a single sender address can trigger per day. A genuine self-removal only ever needs to be requested once — this caps how many confirmation emails a spoofed or repeated From can be used to spam a real artist with. Default: 3.'=>'Nombre màxim de correus electrònics de confirmació d\'autodetirada ("adeu") que una sola adreça remitent pot activar per dia. Una autodetirada real només cal sol·licitar-la una vegada — això limita quants correus de confirmació es poden enviar a un artista real mitjançant un From falsificat o repetit. Valor per defecte: 3.','Community broadcasts per artist per day'=>'Difusions comunitàries per artista i dia','Maximum number of messages a single artist can send to the Community announcement address (Settings → Email) per day. Prevents one member from flooding every other member\'s inbox. Default: 3.'=>'Nombre màxim de missatges que un sol artista pot enviar a l\'adreça d\'anuncis de la Comunitat (Configuració → Correu electrònic) per dia. Evita que un membre inundi la safata d\'entrada de tots els altres membres. Valor per defecte: 3.','Community broadcast max length (characters)'=>'Límit màxim de llargada de la difusió comunitària (caràcters)','Longer messages to the Community announcement address are bounced back to the sender instead of being broadcast — the sender is told to shorten it and resend. Measured in characters, not words, so it applies fairly across languages that don\'t use spaces between words (Chinese, Japanese, Thai, etc.). Every recipient\'s copy is translated individually, so this also caps how much a single message can cost in AI translation calls. Default: 2000. Hard maximum: 20000, regardless of this setting.'=>'Els missatges més llargs a l\'adreça d\'anuncis de la Comunitat es retornen al remitent en lloc de ser difosos — se li indica al remitent que el retalli i el torni a enviar. Es mesura en caràcters, no en paraules, així que s\'aplica de manera justa a llengües que no fan servir espais entre paraules (xinès, japonès, tailandès, etc.). La còpia de cada destinatari es tradueix individualment, de manera que això també limita quant pot costar un sol missatge en crides de traducció d\'IA. Valor per defecte: 2000. Màxim absolut: 20000, independentment d\'aquesta configuració.','Admission vote threshold (%)'=>'Llindar de votació d\'admissió (%)','Percentage of active artists that must vote yes for admission. Combined with the minimum floor below.'=>'Percentatge d\'artistes actius que han de votar sí per a l\'admissió. Combinat amb el mínim inferior.','Admission minimum votes'=>'Vots mínims d\'admissió','Absolute minimum positive votes required regardless of the percentage above.'=>'Nombre mínim absolut de vots positius requerits independentment del percentatge anterior.','Voting window (days)'=>'Finestra de votació (dies)','Days an application stays open. If the threshold is not reached within this window the application is rejected.'=>'Dies que una sol·licitud roman oberta. Si el llindar no s\'assoleix dins d\'aquesta finestra, la sol·licitud es rebutja.','Resolved application retention (days)'=>'Retenció de sol·licituds resoltes (dies)','A rejected, withdrawn, or left application\'s email, name, biography, statement, and portfolio link are anonymized by the daily cleanup after this many days — the application record itself (status and dates) is kept for admission history. A banned artist\'s biography/statement/portfolio are anonymized on the same schedule, but their email is deliberately kept so the ban stays enforceable. Default: 180 days.'=>'El correu electrònic, el nom, la biografia, la declaració i l\'enllaç al portafolis d\'una sol·licitud rebutjada, retirada o abandonada s\'anonimitzen amb la neteja diària després d\'aquests dies — el registre de la sol·licitud en si (estat i dates) es conserva per a l\'historial d\'admissió. La biografia/declaració/portafolis d\'un artista vetat s\'anonimitzen amb la mateixa programació, però el seu correu electrònic es conserva deliberadament perquè el vet continuï sent aplicable. Valor per defecte: 180 dies.','After applying, send artists to'=>'Després de presentar la sol·licitud, envia els artistes a','Optional — pick a page explaining the vouching process and what happens next. When the application is submitted successfully, the artist is redirected there instead of just seeing an inline confirmation message. Leave as "None" to keep the inline message only.'=>'Opcional — tria una pàgina que expliqui el procés de validació i què passarà després. Quan la sol·licitud s\'envia correctament, l\'artista és redirigit allí en lloc de veure només un missatge de confirmació en línia. Deixa-ho com a "Cap" per mantenir només el missatge en línia.','Community size cap'=>'Límit de mida de la comunitat','Maximum number of admitted artists. When full, new applications join a waitlist instead of being rejected, and a freed slot admits the next in line. Set to 0 for no cap. The community can also vote to change this.'=>'Nombre màxim d\'artistes admesos. Quan s\'omple, les noves sol·licituds passen a una llista d\'espera en lloc de ser rebutjades, i una plaça alliberada admet la següent persona de la llista. Defineix-ho a 0 per no tenir límit. La comunitat també pot votar per canviar això.','Cap-change co-signers required'=>'Co-signants requerits per al canvi del límit','How many artists must co-sign a proposal to change the community size cap before it opens as a full community vote.'=>'Quants artistes han de co-signar una proposta per canviar el límit de mida de la comunitat abans que s\'obri com una votació comunitària completa.','Cap-change vote window (days)'=>'Finestra de votació per al canvi del límit (dies)','Days a community cap-change vote stays open. A strict majority of active artists voting yes adopts the new cap.'=>'Dies que una votació de canvi del límit comunitari roman oberta. Una majoria estricta d\'artistes actius votant sí adopta el nou límit.','Removal nominations required'=>'Nominacions de retirada requerides','Number of artist nominations needed before a community removal vote opens. Admins can bypass this threshold.'=>'Nombre de nominacions d\'artistes necessàries abans que s\'obri una votació comunitària de retirada. Els administradors poden saltar-se aquest llindar.','Removal vote window (days)'=>'Finestra de votació de retirada (dies)','Days a community removal vote stays open. A majority (>50%) of active artists must vote yes for removal to proceed.'=>'Dies que una votació comunitària de retirada roman oberta. Una majoria (>50%) dels artistes actius ha de votar sí perquè la retirada tiri endavant.','Invitation intro'=>'Introducció de la invitació','Agnosis is a small, self-hosted home for artists who\'d rather make work than manage a platform. There\'s no algorithm deciding who sees your art, no portfolio site to maintain, and no account to configure — just your work, published and translated automatically for a global audience.

Being part of the community is simple: Fellow artists vouch for new applicants, and everyone keeps full ownership of what they publish; you can leave at any time and take your work with you.

Once admitted, you submit new work by sending it as an email — no dashboard, no forms and you can update, promote or remove your artwork as well sending an email. You can find more information visiting the agnosis.art website.'=>'Agnosis és una petita llar autoallotjada per a artistes que prefereixen fer obra abans que gestionar una plataforma. No hi ha cap algoritme que decideixi qui veu la teva art, no hi ha cap web de portafolis per mantenir i no hi ha cap compte per configurar — només la teva obra, publicada i traduïda automàticament per a un públic global.

Formar part de la comunitat és senzill: altres artistes avalen els nous sol·licitants, i tothom conserva la plena propietat del que publica; pots marxar en qualsevol moment i endur-te la teva obra.

Un cop admès, envies nova obra per correu electrònic — sense tauler de control, sense formularis i també pots actualitzar, promocionar o eliminar la teva obra simplement enviant un correu electrònic. Pots trobar més informació visitant el web agnosis.art.','Shown near the top of the "Send Invitation" email below (an "Apply to join" link and site name follow automatically — no need to add either here). Two or three short paragraphs is plenty. Standing copy, not cleared after use like the newsletter intros above — translated automatically when an invitation is sent in a language other than the site\'s own.'=>'Es mostra prop de la part superior del correu electrònic "Envia la invitació" de més avall (un enllaç "Sol·licita unir-te" i el nom del lloc s\'afegeixen automàticament — no cal afegir cap dels dos aquí). Amb dues o tres paràgrafs curts n\'hi ha prou. Text persistent, que no es buida després d\'usar-se com les introduccions del butlletí de més amunt — es tradueix automàticament quan s\'envia una invitació en un idioma diferent del propi del lloc.','Transaction fee (%)'=>'Comissió de transacció (%)','Percentage retained by this node on donations and art sales. Artists pay nothing up front.'=>'Percentatge retingut per aquest node sobre les donacions i les vendes d\'art. Els artistes no paguen res per avançat.','Sender name'=>'Nom del remitent','Name shown as the sender of digest emails. Leave blank to use the site name.'=>'Nom mostrat com a remitent dels correus electrònics de resum. Deixa-ho en blanc per utilitzar el nom del lloc.','Sender email address'=>'Adreça de correu electrònic del remitent','Dedicated From: address for both newsletters, e.g. newsletter@agnosis.art — keeps digest mail separate from the site\'s admin email for deliverability and so artists can filter it. Leave blank to use the admin email. Must be a valid, deliverable address on your domain (SPF/DKIM configured) or messages may be marked as spam.'=>'Adreça dedicada De: per a tots dos butlletins, per exemple newsletter@agnosis.art — manté el correu del resum separat del correu d\'administració del lloc per millorar l\'entregabilitat i perquè els artistes el puguin filtrar. Deixa-ho en blanc per usar el correu d\'administració. Ha de ser una adreça vàlida i entregable del teu domini (SPF/DKIM configurats) o els missatges poden ser marcats com a correu brossa.','Auto-draft newsletter intros'=>'Genera automàticament esborranys d\'introduccions del butlletí','When enabled, Agnosis drafts an intro via AI ahead of each issue (see the lead time below), saves it to that newsletter\'s intro field, and emails you to review it — unless you\'ve already written one for that cycle. Disable to leave both intro fields exactly as you left them, always.'=>'Quan està activat, Agnosis redacta una introducció amb IA abans de cada número (vegeu el temps d\'antelació més avall), la desa al camp d\'introducció d\'aquell butlletí i t\'envia un correu perquè la revisis — tret que ja n\'hagis escrit una per a aquell cicle. Desactiva-ho per deixar tots dos camps d\'introducció exactament com els vas deixar, sempre.','Draft intro this many hours ahead'=>'Redacta l\'esborrany d\'aquesta introducció amb tantes hores d\'antelació','How long before an issue is due Agnosis proposes an AI-drafted intro. Only takes effect when auto-drafting (above) is enabled. Default: 24.'=>'Quant temps abans que un número vença Agnosis proposa una introducció redactada per IA. Només té efecte quan la generació automàtica d\'esborranys (a dalt) està activada. Per defecte: 24.','Artist newsletter'=>'Butlletí dels artistes','Admitted artists are auto-enrolled (they can unsubscribe from any issue with one click). Community digest: recent activity, new members, open votes.'=>'Els artistes admesos s\'hi inscriuen automàticament (poden donar-se de baixa de qualsevol número amb un sol clic). Resum de la comunitat: activitat recent, nous membres, vots oberts.','Artist newsletter frequency (days)'=>'Freqüència del butlletí dels artistes (dies)','Default 30 ≈ monthly. A new issue is prepared once this many days have passed since the last one was sent.'=>'Per defecte 30 ≈ mensual. Es prepara un número nou quan han passat tants dies des de l\'enviament de l\'últim.','Artist newsletter intro'=>'Introducció del butlletí dels artistes','Optional note prepended to the next artist issue only — cleared automatically once that issue is queued. Leave blank to send the auto-digest with no intro. If left blank, Agnosis drafts one automatically from what\'s new about a day before the issue sends, and emails you to review it first — write your own here any time to skip that.'=>'Nota opcional que s’afegeix només al següent número de l’artista — es neteja automàticament un cop aquest número queda a la cua. Deixa-ho en blanc per enviar el resum automàtic sense introducció. Si es deixa en blanc, Agnosis en redacta una automàticament amb les novetats aproximadament un dia abans que s’enviï el número, i t’envia un correu perquè el revisis primer — escriu el teu propi text aquí en qualsevol moment per ometre-ho.','Public newsletter'=>'Butlletí públic','Visitors subscribe via the agnosis/newsletter-signup block (double opt-in). Digest: new artwork and events published since the last issue.'=>'Els visitants s’hi subscriuen mitjançant el bloc agnosis/newsletter-signup (doble opt-in). Resum: obres noves i esdeveniments publicats des de l’últim número.','Public newsletter frequency (days)'=>'Freqüència del butlletí públic (dies)','Default 30 ≈ monthly.'=>'Per defecte, 30 ≈ mensual.','Public newsletter intro'=>'Introducció del butlletí públic','Optional note prepended to the next public issue only — cleared automatically once that issue is queued. If left blank, Agnosis drafts one automatically from what\'s new about a day before the issue sends, and emails you to review it first — write your own here any time to skip that.'=>'Nota opcional que s’afegeix només al següent número públic — es neteja automàticament un cop aquest número queda a la cua. Si es deixa en blanc, Agnosis en redacta una automàticament amb les novetats aproximadament un dia abans que s’enviï el número, i t’envia un correu perquè el revisis primer — escriu el teu propi text aquí en qualsevol moment per ometre-ho.','Send batch size'=>'Mida del lot d’enviament','Recipients emailed per 5-minute cron tick. Lower this if your host throttles outbound mail; raise it for faster delivery on hosts with generous limits.'=>'Destinataris enviats per cada tic del cron de 5 minuts. Redueix-ho si el teu allotjament limita el correu sortint; augmenta-ho per a un lliurament més ràpid en allotjaments amb límits generosos.','Self-hosting comfort threshold'=>'Llindar de comoditat per a l’allotjament propi','Advisory only — self-hosted sending keeps working above this count. Once confirmed public subscribers pass it, this page shows a reminder to consider an email service provider (e.g. Brevo\'s free tier) instead.'=>'Només informatiu — l’enviament allotjat en servidor propi continua funcionant per sobre d’aquest nombre. Quan els subscriptors públics confirmats el superin, aquesta pàgina mostra un recordatori per considerar un proveïdor de servei de correu electrònic (per exemple, el pla gratuït de Brevo) en lloc d’això.','Sends a minimal ping ("Reply with the word: ping") using the configured API key.'=>'Envia un ping mínim ("Respon amb la paraula: ping") utilitzant la clau de l’API configurada.','Sends a minimal ping using the configured API key.'=>'Envia un ping mínim utilitzant la clau de l’API configurada.','WordPress AI Client'=>'Client d’IA de WordPress','Checks that wp_ai_client_prompt() is available (WordPress 7.0+) and a text-generation model is configured.'=>'Comprova que wp_ai_client_prompt() estigui disponible (WordPress 7.0+) i que hi hagi configurat un model de generació de text.','Test AI Providers'=>'Prova els proveïdors d’IA','Test %s'=>'Prova %s','Bot Protection'=>'Protecció contra bots','Turnstile is configured.'=>'Turnstile està configurat.','The Join application form and the Newsletter Subscribe form both require human verification before they accept a submission.'=>'Tant el formulari de sol·licitud d’adhesió com el formulari de subscripció al butlletí requereixen verificació humana abans d’acceptar una tramesa.','Turnstile is not configured.'=>'Turnstile no està configurat.','Your Join application form is public — anyone can submit an application, and a submitted (and confirmed) application still emails every admitted artist and admin. Right now the only thing standing between that form and an automated bot is a fixed 5-submissions-per-minute-per-IP limit, which a distributed bot can work around entirely. Add a Cloudflare Turnstile site key and secret key above to require human verification on both the Join form and the Newsletter Subscribe form.'=>'El teu formulari de sol·licitud d’adhesió és públic — qualsevol pot enviar una sol·licitud, i una sol·licitud enviada (i confirmada) encara envia un correu a tots els artistes i administradors admesos. Ara mateix, l’únic que separa aquest formulari d’un bot automatitzat és un límit fix de 5 enviaments per minut per IP, que un bot distribuït pot esquivar del tot. Afegeix una clau de lloc i una clau secreta de Cloudflare Turnstile a dalt per requerir verificació humana tant al formulari d’adhesió com al formulari de subscripció al butlletí.','OpenAI'=>'OpenAI','Anthropic'=>'Anthropic','AI Processing & Privacy Policy'=>'Política de privacitat de processament i privadesa de la IA','A Privacy Policy page is set.'=>'Hi ha definida una pàgina de Política de privacitat.','Suggested wording covering %s and public federation was added to it automatically — review it under Settings → Privacy → "Guide" before publishing, and check with your provider(s) about their own data processing agreement (DPA) for your compliance obligations.'=>'S’hi ha afegit automàticament una redacció suggerida que cobreix %s i la federació pública — revisa-la a Configuració → Privadesa → "Guia" abans de publicar, i consulta amb el teu(s) proveïdor(s) el seu propi acord de tractament de dades (DPA) per a les teves obligacions de compliment.','No Privacy Policy page is set.'=>'No hi ha definida cap pàgina de Política de privacitat.','Submitted artwork, text, and visitor contact messages are sent to %s for processing. Create or choose a page under Settings → Privacy — this plugin has already prepared suggested wording you\'ll find there under "Guide". You may also want to review that provider\'s data processing agreement (DPA) for your own compliance obligations.'=>'Els enviaments d’obres, text i missatges de contacte dels visitants s’envien a %s per al seu processament. Crea o tria una pàgina a Configuració → Privadesa — aquest connector ja ha preparat una redacció suggerida que hi trobaràs a "Guia". També potser voldràs revisar l’acord de tractament de dades (DPA) d’aquest proveïdor per a les teves pròpies obligacions de compliment.','Go to Settings → Privacy'=>'Ves a Configuració → Privadesa','Debug Files'=>'Fitxers de depuració','Currently'=>'Actualment','Enabled'=>'Activat','Disabled'=>'Desactivat','Forced ON by the AGNOSIS_DEBUG constant in wp-config.php — the checkbox above has no effect until that line is removed.'=>'FORÇAT ACTIVAT per la constant AGNOSIS_DEBUG a wp-config.php — la casella de selecció de dalt no té efecte fins que s’elimini aquesta línia.','Forced OFF by the AGNOSIS_DEBUG constant in wp-config.php — the checkbox above has no effect until that line is removed.'=>'FORÇAT DESACTIVAT per la constant AGNOSIS_DEBUG a wp-config.php — la casella de selecció de dalt no té efecte fins que s’elimini aquesta línia.','Directory'=>'Directori','Filter with agnosis_debug_dir to redirect debug output elsewhere.'=>'Filtra amb agnosis_debug_dir per redirigir la sortida de depuració a un altre lloc.','.txt file(s) in the directory'=>'fitxer(s) .txt al directori','Delete all .txt files in the debug directory? The directory itself stays in place so future debug writes still land cleanly.'=>'Eliminar tots els fitxers .txt del directori de depuració? El directori en si es manté, de manera que futures escriptures de depuració continuaran arribant-hi correctament.','Clear Debug Files'=>'Neteja els fitxers de depuració','Term Translation Cache'=>'Memòria cau de traducció de termes','Cached translations'=>'Traduccions en memòria cau','AI-translated tag/medium term names, cached so the same term always gets the same translated label instead of a fresh AI phrasing per post. Renaming a term already clears its own cached entry automatically; use the button below only if a cached translation itself is wrong.'=>'Noms de termes d’etiquetes/mitjans traduïts amb IA, emmagatzemats en memòria cau perquè el mateix terme tingui sempre la mateixa etiqueta traduïda en lloc d’una nova formulació d’IA per a cada publicació. Canviar el nom d’un terme ja esborra automàticament la seva pròpia entrada en memòria cau; fes servir el botó de sota només si una traducció en memòria cau és incorrecta.','Clear every cached term translation? Nothing is deleted from your site — terms will simply be re-translated by AI the next time they\'re needed.'=>'Voleu esborrar totes les traduccions de termes en memòria cau? No s’elimina res del vostre lloc — simplement es tornaran a traduir amb IA la propera vegada que siguin necessàries.','Clear Term Translation Cache'=>'Neteja la memòria cau de traducció de termes','Pipeline Logs'=>'Registres de la canalització','Clear all log entries?'=>'Voleu esborrar totes les entrades del registre?','Clear All'=>'Esborra-ho tot','%d entries total. Logs are pruned automatically according to the Inbox retention setting.'=>'%d entrades en total. Els registres es purguen automàticament segons la configuració de retenció de la safata d’entrada.','No log entries yet.'=>'Encara no hi ha entrades de registre.','Time'=>'Hora','Level'=>'Nivell','Context'=>'Context','Inbox Tools'=>'Eines de la safata d\'entrada','Test connection'=>'Prova la connexió','Test IMAP Connection'=>'Prova la connexió IMAP','Connects to the configured mailbox and reports the total and unseen message count.'=>'Es connecta a la bústia configurada i informa del nombre total de missatges i del nombre de missatges no llegits.','Poll inbox now'=>'Comprova la safata d\'entrada ara','Poll Inbox Now'=>'Comprova la safata d\'entrada ara','Fetches unseen messages immediately without waiting for WP-Cron. Then click "Process Pending Queue" to run the AI pipeline.'=>'Recupera immediatament els missatges no llegits sense esperar al WP-Cron. Després fes clic a "Processa la cua pendent" per executar la canonada d\'IA.','Process queue'=>'Processa la cua','Process Pending Queue'=>'Processa la cua pendent','Immediately runs the AI pipeline on all pending queue items without waiting for WP-Cron. Use this to test the end-to-end flow after a poll.'=>'Executa immediatament la canonada d\'IA sobre tots els elements pendents de la cua sense esperar al WP-Cron. Fes servir això per provar el flux de principi a fi després d\'una comprovació de la safata d\'entrada.','Force reprocess'=>'Força el reprocessament','Force Reprocess Inbox'=>'Força el reprocessament de la safata d\'entrada','Resets failed/stuck/orphaned queue rows back to pending, then immediately polls for unprocessed messages. Then click "Process Pending Queue" to run the AI pipeline. Already-published artworks with valid posts are never re-processed.'=>'Reinicia les files de la cua fallides/encallades/orfes a pendent i, tot seguit, comprova immediatament si hi ha missatges no processats. Després fes clic a "Processa la cua pendent" per executar la canonada d\'IA. Les obres ja publicades amb entrades vàlides no es tornen a processar mai.','Deliverability'=>'Entregabilitat','A diagnostic check only — nothing here changes how mail is sent. On ordinary hosting (PHP mail(), no SMTP plugin), mail sent from an address that doesn\'t match your site\'s own domain, or from a domain with no SPF/DMARC record at all, is increasingly likely to land in spam or be rejected outright by large mailbox providers. If any row below looks wrong, the most reliable fix is installing an SMTP-sending plugin (WP Mail SMTP, Post SMTP, FluentSMTP, and others all work) configured against a real transactional mail provider, and adding SPF/DMARC records for the domain you send from at your DNS host.'=>'Només una comprovació de diagnòstic: aquí no es canvia res de com s\'envia el correu. En allotjaments habituals (PHP mail(), sense connector SMTP), el correu enviat des d\'una adreça que no coincideixi amb el domini del teu lloc, o des d\'un domini sense cap registre SPF/DMARC, té cada vegada més probabilitats d\'acabar a correu brossa o de ser rebutjat directament pels grans proveïdors de bústies. Si alguna fila de sota sembla incorrecta, la solució més fiable és instal·lar un connector d\'enviament SMTP (WP Mail SMTP, Post SMTP, FluentSMTP i altres funcionen) configurat amb un proveïdor real de correu transaccional, i afegir registres SPF/DMARC per al domini des del qual envies al teu proveïdor DNS.','From identity'=>'Identitat del remitent','Domain matches site?'=>'El domini coincideix amb el del lloc?','SPF record'=>'Registre SPF','DMARC record'=>'Registre DMARC','SMTP plugin'=>'Connector SMTP','Detected: %s'=>'Detectat: %s','None of the common SMTP-sending plugins were detected — this site is likely relying on PHP\'s built-in mail(), which most hosts deliver poorly through.'=>'No s\'ha detectat cap dels connectors habituals d\'enviament SMTP: aquest lloc probablement depèn del mail() integrat de PHP, que la majoria d\'allotjaments lliuren amb poca fiabilitat.','Send a real test email to:'=>'Envia un correu de prova real a:','Send Test'=>'Envia la prova','Sends one plain-text email from the same community identity used for review/vote/vouch mail. Reaching your inbox is a good sign; landing in spam or not arriving at all confirms a real deliverability problem regardless of what the checks above say.'=>'Envia un sol correu electrònic en text pla des de la mateixa identitat de la comunitat que s\'utilitza per al correu de revisió/votació/aval. Que arribi a la safata d\'entrada és un bon senyal; si acaba a correu brossa o no arriba, confirma un problema real d\'entregabilitat, independentment del que diguin les comprovacions anteriors.','Found'=>'Trobat','Not found'=>'No trobat','DNS lookup failed'=>'La consulta DNS ha fallat','Unavailable on this host'=>'No disponible en aquest allotjament','No address configured'=>'No hi ha cap adreça configurada','[TEST] Deliverability check from %s'=>'[PROVA] Comprovació d\'entregabilitat des de %s','This is a one-off deliverability test from your Agnosis Settings → Email Inbox page. If you\'re reading this in your inbox (not spam), the community/transactional From identity is deliverable to this address.'=>'Aquesta és una prova d\'entregabilitat puntual des de la pàgina Agnosis Configuració → Safata d\'entrada de correu electrònic. Si estàs llegint això a la safata d\'entrada (no a correu brossa), la identitat de remitent comunitària/transaccional és entregable a aquesta adreça.','Pending Applications'=>'Sol·licituds pendents','%d application is awaiting email confirmation from the applicant and isn\'t listed below yet.'=>'%d sol·licitud està a l\'espera de la confirmació per correu electrònic del sol·licitant i encara no apareix a la llista de sota.' . "\0" . '%d sol·licituds estan a l\'espera de la confirmació per correu electrònic del sol·licitant i encara no apareixen a la llista de sota.','No pending applications.'=>'No hi ha sol·licituds pendents.','%d positive vote(s) currently required for admission.'=>'Actualment es requereixen %d vot(s) positiu(s) per a l\'admissió.','Applicant'=>'Sol·licitant','Applied'=>'Sol·licitat','Votes'=>'Vots','Bio / Portfolio'=>'Bio / Portafolis','%1$d / %2$d'=>'%1$d / %2$d','Portfolio ↗'=>'Portafolis ↗','Admit'=>'Admet','Reject'=>'Rebutja','No admitted members yet.'=>'Encara no hi ha cap membre admès.','Joined'=>'Unit','Banned until %s'=>'Bandejat fins al %s','Banned'=>'Bandejat','Active'=>'Actiu','This address has bounced or been reported as spam — mail may no longer be reaching this artist.'=>'Aquesta adreça ha rebut rebots o s’ha denunciat com a correu brossa — pot ser que els correus ja no arribin a aquest artista.','⚠ %d bounce'=>'⚠ %d rebot' . "\0" . '⚠ %d rebots','This artist has muted community broadcast messages.'=>'Aquest artista ha silenciat els missatges de difusió de la comunitat.','🔇 Broadcasts muted'=>'🔇 Difusions silenciades','This artist receives one daily digest of open applications instead of an email per application.'=>'Aquest artista rep un resum diari de les sol·licituds obertes en lloc d’un correu per a cada sol·licitud.','📬 Vote digest mode'=>'📬 Mode de resum de vots','Leave the date blank to ban indefinitely. Continue?'=>'Deixa la data en blanc per bandejar-lo indefinidament. Continueu?','Leave blank to ban indefinitely'=>'Deixa en blanc per bandejar-lo indefinidament','Suspend'=>'Suspèn','Permanently delete this artist and all their content? This cannot be undone.'=>'Vols eliminar permanentment aquest artista i tot el seu contingut? Això no es pot desfer.','Open a community removal vote for this artist? All members will be emailed.'=>'Obrir una votació comunitària per retirar aquest artista? S’enviarà un correu electrònic a tots els membres.','Open Vote'=>'Obrir votació','Newsletter Status'=>'Estat del butlletí','You have %1$d confirmed public subscribers, above the configured comfort threshold of %2$d. Self-hosted sending still works, but you may want to connect an email service provider (e.g. Brevo\'s free tier) for better deliverability at this size.'=>'Tens %1$d subscriptors públics confirmats, per sobre del llindar de comoditat configurat de %2$d. L’enviament allotjat al teu servidor continua funcionant, però potser voldràs connectar un proveïdor de serveis de correu electrònic (p. ex. el nivell gratuït de Brevo) per a una millor lliurabilitat amb aquesta mida.','Audience'=>'Audiència','Last sent'=>'Últim enviament','Action'=>'Acció','Failed recipients'=>'Destinataris fallits','Send a test'=>'Envia una prova','%1$d admitted (%2$d opted out)'=>'%1$d admesos (%2$d han optat per no participar)','Sending…'=>'Enviant…','Idle'=>'Inactiu','Send Now'=>'Envia ara','Public'=>'Públic','%1$d confirmed, %2$d pending confirmation, %3$d unsubscribed, %4$d bounced'=>'%1$d confirmats, %2$d pendents de confirmació, %3$d cancel·lats, %4$d amb rebot','By language: %s'=>'Per idioma: %s','Add the "Newsletter Signup" block to any page to let visitors subscribe to the public newsletter. Artists are enrolled automatically and can unsubscribe from any issue with one click.'=>'Afegeix el bloc "Newsletter Signup" a qualsevol pàgina per permetre que els visitants se subscriguin al butlletí públic. Els artistes s’inscriuen automàticament i poden donar-se de baixa de qualsevol número amb un sol clic.','Never'=>'Mai','Unknown'=>'Desconegut','None'=>'Cap','%d failed'=>'%d fallits' . "\0" . '%d fallits','Retry Failed'=>'Torna a provar els fallits','Invite an Artist'=>'Convida un artista','Send a one-off email inviting someone to apply. Nothing is tracked or scheduled — this sends immediately to the address below.'=>'Envia un correu electrònic puntual convidant algú a presentar la sol·licitud. No es fa seguiment ni es programa res: s’envia immediatament a l’adreça de sota.','artist@example.com'=>'artist@example.com','Send Invitation'=>'Envia la invitació','Permission denied.'=>'Permís denegat.','OpenAI API key not configured.'=>'La clau de l’API d’OpenAI no està configurada.','OpenAI connection successful.'=>'La connexió amb OpenAI ha estat correcta.','Anthropic API key not configured.'=>'La clau de l’API d’Anthropic no està configurada.','Anthropic connection successful.'=>'La connexió amb Anthropic ha estat correcta.','WordPress AI Client requires WordPress 7.0 or later.'=>'WordPress AI Client requereix WordPress 7.0 o posterior.','No text-generation model configured. Set one up under Settings → Connectors.'=>'No hi ha cap model de generació de text configurat. Configura’n un a Configuració → Connectors.','WordPress AI Client is available and a text-generation model is configured.'=>'WordPress AI Client està disponible i hi ha un model de generació de text configurat.','Unknown provider.'=>'Proveïdor desconegut.','HTTP %d'=>'HTTP %d','The artist sent no subject line or message with this submission — let the image speak entirely for itself.'=>'L’artista no ha enviat cap assumpte ni missatge amb aquesta tramesa — deixa que la imatge parli completament per si mateixa.','Name'=>'Nom','Bio'=>'Bio','Statement'=>'Declaració','%1$s must be %2$d characters or fewer.'=>'%1$s ha de tenir %2$d caràcters o menys.','Please select your language.'=>'Si us plau, seleccioneu el vostre idioma.','An account with this email address already exists.'=>'Ja existeix un compte amb aquesta adreça electrònica.','This email address belongs to an admitted artist.'=>'Aquesta adreça electrònica pertany a un artista admès.','An application for this email address is already pending.'=>'Ja hi ha una sol·licitud pendent per a aquesta adreça electrònica.','Application not found.'=>'Sol·licitud no trobada.','Only admitted artists can vouch.'=>'Només els artistes admesos poden avalar.','Admin access required.'=>'Cal accés d’administrador.','You cannot vote on your own application.'=>'No pots votar la teva pròpia sol·licitud.','Invalid or incomplete link.'=>'Enllaç no vàlid o incomplet.','This confirmation link is invalid or has already been used.'=>'Aquest enllaç de confirmació no és vàlid o ja s’ha utilitzat.','Confirm your application?'=>'Confirmes la teva sol·licitud?','Your application will open for community review once you confirm below.'=>'La teva sol·licitud s’obrirà a la revisió de la comunitat un cop la confirmis a continuació.','Confirm my application'=>'Confirma la meva sol·licitud','This community is currently full, so your application has joined the waitlist — when a member leaves, the next person in line is welcomed in.'=>'Aquesta comunitat és plena en aquests moments, així que la teva sol·licitud s’ha afegit a la llista d’espera — quan un membre marxi, entrarà la següent persona de la cua.','You\'re all set — the community can now review your application and vote.'=>'Ja està tot llest — ara la comunitat pot revisar la teva sol·licitud i votar.','Application confirmed'=>'Sol·licitud confirmada','Thanks, %s!'=>'Gràcies, %s!','Link error'=>'Error de l’enllaç','Confirm your application to %s'=>'Confirma la teva sol·licitud a %s','Your application to %s'=>'La teva sol·licitud a %s','Application by %s has closed'=>'La sol·licitud de %s s’ha tancat','Welcome to %s'=>'Benvingut a %s','We received your application to %s'=>'Hem rebut la teva sol·licitud a %s','Hi %s,'=>'Hola, %s,','One last step before %s can review your application: confirm this is really your email address.'=>'L’últim pas abans que %s pugui revisar la teva sol·licitud: confirma que aquesta és realment la teva adreça electrònica.','If you didn\'t apply, simply ignore this email — nothing happens until this link is clicked.'=>'Si no has fet la sol·licitud, simplement ignora aquest correu — no passarà res fins que es faci clic en aquest enllaç.','%s — art blooming out of oblivion'=>'%s — art florint fora de l’oblit','Thank you for applying to %s. Your application has been received and is now open for community review.'=>'Gràcies per sol·licitar entrar a %s. Hem rebut la teva sol·licitud i ara està oberta a la revisió de la comunitat.','The community has %d days to vote. We will let you know the outcome by email.'=>'La comunitat té %d dies per votar. Et comunicarem el resultat per correu electrònic.','New application: %1$s wants to join %2$s'=>'Nova sol·licitud: %1$s vol unir-se a %2$s','%1$s has applied to join %2$s. You have %3$d days to vote.'=>'%1$s ha sol·licitat unir-se a %2$s. Tens %3$d dies per votar.','Portfolio:'=>'Portafolis:','Vote YES'=>'Vota SÍ','Vote NO'=>'Vota NO','You can change your vote at any time within the voting window.'=>'Pots canviar el teu vot en qualsevol moment dins del període de votació.','Thank you for applying to %s. Unfortunately, your application did not receive enough votes within the voting window.'=>'Gràcies per sol·licitar entrar a %s. Malauradament, la teva sol·licitud no ha rebut prou vots dins del període de votació.','You are welcome to apply again in the future.'=>'Pots tornar a presentar la sol·licitud en el futur.','The application by %s has closed without reaching the admission threshold. No action required.'=>'La sol·licitud de %s s’ha tancat sense arribar al llindar d’admissió. No cal fer res.','The %s community has admitted you as an artist. Welcome!'=>'La comunitat %s t’ha admès com a artista. Benvingut!','Your gallery:'=>'La teva galeria:','Your submissions:'=>'Les teves trameses:','How to share your work — send an email to:'=>'Com compartir el teu treball — envia un correu electrònic a:','Subject line conventions:'=>'Conventions de l’assumpte:','Artwork (default) — any subject'=>'Obra (per defecte) — qualsevol tema','[Biography] — biography update'=>'[Biografia] — actualització de la biografia','[Event] — event announcement'=>'[Esdeveniment] — anunci d’esdeveniment','[Photo] — publish as-is, no AI enhancement (fallback for mail apps without To: aliases)'=>'[Foto] — publica tal qual, sense millora amb IA (alternativa per a clients de correu sense àlies To:)','[Pure] — publish exactly as sent, no AI at all (fallback for mail apps without To: aliases)'=>'[Pur] — publica exactament com s’ha enviat, sense IA de cap mena (alternativa per a clients de correu sense àlies To:)','To leave the network and delete your account:'=>'Per sortir de la xarxa i suprimir el teu compte:','Send any email (no attachment needed). You will receive a confirmation link — nothing is deleted until you click it.'=>'Envia qualsevol correu electrònic (no cal cap adjunt). Rebràs un enllaç de confirmació — no se suprimeix res fins que el facis clic.','No login is needed to work with Agnosis — everything above happens by email. If you\'d also like to use the site\'s optional online features (like previewing a submission before it publishes), you can set up a password whenever you like using'=>'No cal iniciar sessió per treballar amb Agnosis — tot això passa per correu electrònic. Si també vols fer servir les funcions en línia opcionals del lloc (com previsualitzar una tramesa abans que es publiqui), pots configurar una contrasenya quan vulguis amb','password recovery'=>'recuperació de contrasenya','Submit artwork'=>'Envia obra','Submit biography'=>'Envia biografia','Submit event'=>'Envia esdeveniment','Replace artwork (subject: exact title)'=>'Substitueix l’obra (assumpte: títol exacte)','Remove artwork (subject: exact title)'=>'Elimina l’obra (assumpte: títol exacte)','Feature artwork in the shared gallery (subject: exact title)'=>'Destaca l’obra a la galeria compartida (assumpte: títol exacte)','Photo-only — publish as-is, no AI enhancement'=>'Només foto — publica tal qual, sense millora amb IA','Pure — publish exactly as sent, no AI at all'=>'Pur — publica exactament com s’ha enviat, sense IA de cap mena','About %s'=>'Sobre %s','%1$s — %2$s'=>'%1$s — %2$s','[%s] Your community message was not sent — too long'=>'[%s] El teu missatge a la comunitat no s’ha enviat — massa llarg','Hi %1$s,

Your message to the community was %2$d characters long — the current limit is %3$d. It was not sent to anyone.

Every recipient\'s copy is translated individually into their own language, so a very long message is costly to translate for the whole community. Please shorten it and send it again.

— %4$s'=>'Hola %1$s,

El teu missatge a la comunitat tenia %2$d caràcters — el límit actual és %3$d. No s’ha enviat a ningú.

La còpia de cada destinatari es tradueix individualment a la seva pròpia llengua, així que un missatge molt llarg és costós de traduir per a tota la comunitat. Esmola’l una mica i torna a enviar-lo.

— %4$s','[%s] Your community message was not sent — no content found'=>'[%s] El teu missatge a la comunitat no s’ha enviat — no s’ha trobat contingut','Hi %1$s,

Your message to the community had no subject or message text that could be found — this often happens when an email client sends an HTML-only message with no plain-text version included. It was not sent to anyone.

Please try sending it again with plain text included.

— %2$s'=>'Hola %1$s,

No s’ha trobat cap assumpte ni text de missatge al teu missatge a la comunitat — això sovint passa quan un client de correu envia un missatge només en HTML i no inclou cap versió en text pla. No s’ha enviat a ningú.

Torna a provar d’enviar-lo amb text pla inclòs.

— %2$s','[%1$s] Community message from %2$s'=>'[%1$s] Missatge de la comunitat de %2$s','%1$s <%2$s> sent a message to the community:'=>'%1$s <%2$s> ha enviat un missatge a la comunitat:','Subject: %s'=>'Assumpte: %s','Hit reply to respond — your reply goes back to the whole community, translated automatically, just like this message.'=>'Respon fent clic a respon — la teva resposta torna a tota la comunitat, traduïda automàticament, igual que aquest missatge.','This message was sent by %s.'=>'Aquest missatge ha estat enviat per %s.','%1$s via %2$s'=>'%1$s via %2$s','no limit'=>'sense límit','Hi %1$s,

The %2$s community has opened a vote to change the membership size cap to %3$s. The vote closes on %4$s.

A strict majority of active members (more than 50%%) must vote yes for the new cap to be adopted. Sign in to your account to cast your vote.

— %2$s'=>'Hola %1$s,

La comunitat de %2$s ha obert una votació per canviar el límit de mida de membres a %3$s. La votació acaba el %4$s.

Cal una majoria estricta dels membres actius (més del 50%%) perquè el nou límit s’adopti. Inicia sessió al teu compte per emetre el teu vot.

— %2$s','Community size-cap vote open at %s'=>'Votació oberta sobre el límit de mida de la comunitat a %s','Community size cap changed at %s'=>'Límit de mida de la comunitat canviat a %s','The community voted to change the membership size cap to %1$s (proposal #%2$d). The new cap is now in effect.'=>'La comunitat ha votat canviar el límit de mida dels membres a %1$s (proposta #%2$d). El nou límit ja és en vigor.','Community size-cap proposal did not pass at %s'=>'La proposta de límit de mida de la comunitat no ha prosperat a %s','A community vote to change the membership size cap (proposal #%1$d) closed without a majority. The cap is unchanged.'=>'Una votació de la comunitat per canviar el límit de mida dels membres (proposta #%1$d) s’ha tancat sense majoria. El límit no ha canviat.','Only community members can do this.'=>'Només els membres de la comunitat poden fer això.','The cap must be zero or a positive number.'=>'El límit ha de ser zero o un nombre positiu.','That is already the current cap.'=>'Aquest ja és el límit actual.','A different cap proposal is already under way. Resolve or co-sign that one first.'=>'Ja hi ha una altra proposta de límit en marxa. Resoleu-la o copatrocineu-la primer.','No active proposal to co-sign.'=>'No hi ha cap proposta activa per copatrocinar.','Proposal not found.'=>'No s’ha trobat la proposta.','This vote is not currently open.'=>'Aquesta votació no està oberta actualment.','This artist can\'t be reached through this form right now.'=>'Ara mateix no es pot contactar amb aquest artista mitjançant aquest formulari.','Thanks — your message has been sent.'=>'Gràcies — el teu missatge s’ha enviat.','Spam, scams, or unsolicited commercial advertising unrelated to genuinely contacting the artist about their work'=>'Correu brossa, estafes o publicitat comercial no sol·licitada no relacionada amb contactar genuïnament amb l’artista sobre la seva obra','Flagged by automatic content review.'=>'Marcat per la revisió automàtica del contingut.','New message from %s via your Agnosis contact form'=>'Missatge nou de %s a través del teu formulari de contacte d’Agnosis','From: %s'=>'De: %s','(no name provided)'=>'(no s’ha proporcionat cap nom)','Email: %s'=>'Correu electrònic: %s','Original message, as submitted:'=>'Missatge original, tal com es va enviar:','Your name (optional)'=>'El teu nom (opcional)','Your email address'=>'La teva adreça electrònica','you@example.com'=>'tu@exemple.com','Send message'=>'Envia el missatge','Thanks — your message has been sent. You can reach out to this artist again a little later.'=>'Gràcies — el teu missatge s\'ha enviat. Pots tornar a contactar amb aquest artista una mica més tard.','Something went wrong. Please try again.'=>'Alguna cosa ha anat malament. Torna-ho a provar.','Authentication required.'=>'Cal autenticació.','This field cannot be edited here.'=>'Aquest camp no es pot editar aquí.','That date could not be understood.'=>'Aquesta data no s\'ha pogut entendre.','That does not look like a valid timezone (e.g. "Europe/Madrid").'=>'Això no sembla una zona horària vàlida (p. ex. "Europe/Madrid").','That does not look like a valid link (must start with http:// or https://).'=>'Això no sembla un enllaç vàlid (ha de començar per http:// o https://).','The title cannot be empty.'=>'El títol no pot estar buit.','Saved — translations will update within a few minutes.'=>'Desat — les traduccions s\'actualitzaran d\'aquí a uns minuts.','No image file was received.'=>'No s\'ha rebut cap fitxer d\'imatge.','Please upload a JPEG, PNG, WebP, or GIF image.'=>'Carrega una imatge JPEG, PNG, WebP o GIF.','The uploaded file could not be read.'=>'No s\'ha pogut llegir el fitxer carregat.','Untitled'=>'Sense títol','Photo replaced — the original is kept and can be restored later.'=>'Foto substituïda — l\'original es conserva i es podrà restaurar més tard.','There is no photo to restore.'=>'No hi ha cap foto per restaurar.','No earlier version of this photo was found.'=>'No s\'ha trobat cap versió anterior d\'aquesta foto.','Restored the earlier photo.'=>'La foto anterior s\'ha restaurat.','Only admitted artists may edit their own content.'=>'Només els artistes admesos poden editar el seu propi contingut.','Content not found.'=>'Contingut no trobat.','Only published content can be corrected here.'=>'Aquí només es pot corregir el contingut publicat.','You may only edit your own content.'=>'Només pots editar el teu propi contingut.','This page is not in your own language. Edit the version in your language instead.'=>'Aquesta pàgina no està en la teva llengua. Edita, en canvi, la versió en la teva llengua.','Unsupported field target.'=>'Destinació del camp no compatible.','Save'=>'Desa','Cancel'=>'Cancel·la','Saving…'=>'Desant…','Replace photo'=>'Substitueix la foto','Uploading…'=>'Carregant…','Restore earlier photo'=>'Restaura la foto anterior','Restoring…'=>'Restaurant…','You have left'=>'Has marxat','Your account and everything you published on %s have been permanently deleted. Nothing tied to you is stored here anymore.'=>'El teu compte i tot el que has publicat a %s s\'ha suprimit permanentment. Ja no es conserva res vinculat a tu aquí.','Link expired or already used'=>'Enllaç caducat o ja utilitzat','This confirmation link has already been used or is no longer valid. If you still want to leave, please request removal again from your account.'=>'Aquest enllaç de confirmació ja s\'ha utilitzat o ja no és vàlid. Si encara vols marxar, torna a sol·licitar l\'eliminació des del teu compte.','You must be logged in.'=>'Has d\'haver iniciat sessió.','Artist access required.'=>'Cal accés d\'artista.','No active membership found for this account.'=>'No s\'ha trobat cap afiliació activa per a aquest compte.','You cannot nominate yourself for removal.'=>'No et pots proposar tu mateix per a l\'eliminació.','Artist not found.'=>'No s\'ha trobat l\'artista.','Removal request not found.'=>'No s\'ha trobat la sol·licitud d\'eliminació.','You cannot vote on your own removal.'=>'No pots votar sobre la teva pròpia eliminació.','Confirm your departure from %s'=>'Confirma la teva marxa de %s','Hi %1$s,

We received a request to remove your account and all your published work from %2$s.

If you made this request, click the link below to confirm. This action is permanent and cannot be undone.

%3$s

If you did not make this request, you can ignore this email — your account remains unchanged.

— %2$s'=>'Hola %1$s,

Hem rebut una sol·licitud per eliminar el teu compte i tota la teva obra publicada de %2$s.

Si has fet aquesta sol·licitud, fes clic a l\'enllaç següent per confirmar-la. Aquesta acció és permanent i no es pot desfer.

%3$s

Si no has fet aquesta sol·licitud, pots ignorar aquest correu — el teu compte no es veurà afectat.

— %2$s','An artist has left %s'=>'Un artista ha marxat de %s','%1$s has confirmed their departure from %2$s.

Their account and all published work have been permanently deleted.

— %2$s'=>'%1$s ha confirmat la seva sortida de %2$s.

El seu compte i tota la feina publicada han estat eliminats permanentment.

— %2$s','You\'ve left %s'=>'Has deixat %s','Hi %1$s,

This confirms that your account and everything you published on %2$s have been permanently deleted, as you requested.

Nothing tied to you — your artwork, biography, events, or account details — is stored on %2$s anymore.

If you didn\'t request this, please contact the site admin right away.

— %2$s'=>'Hola %1$s,

Això confirma que el teu compte i tot el que has publicat a %2$s han estat eliminats permanentment, tal com has sol·licitat.

Ja no es conserva res vinculat a tu — la teva obra, biografia, esdeveniments o dades del compte — a %2$s.

Si no has sol·licitat això, posa\'t en contacte amb l\'administrador del lloc immediatament.

— %2$s','Hi %1$s,

Your membership at %2$s has been temporarily suspended until %3$s.

You will be automatically reinstated on that date. If you have questions, please contact the site admin.

— %2$s'=>'Hola %1$s,

La teva pertinença a %2$s ha estat suspesa temporalment fins al %3$s.

Seràs restablert automàticament en aquesta data. Si tens cap dubte, posa\'t en contacte amb l\'administrador del lloc.

— %2$s','Hi %1$s,

Your membership at %2$s has been suspended.

If you have questions, please contact the site admin.

— %2$s'=>'Hola %1$s,

La teva pertinença a %2$s ha estat suspesa.

Si tens cap dubte, posa\'t en contacte amb l\'administrador del lloc.

— %2$s','Your membership at %s has been suspended'=>'La teva pertinença a %s ha estat suspesa','Hi %1$s,

Your temporary suspension at %2$s has ended and your membership has been reinstated. You can now log in and submit work as before.

— %2$s'=>'Hola %1$s,

La teva suspensió temporal a %2$s ha finalitzat i la teva pertinença ha estat restablerta. Ara ja pots iniciar sessió i enviar obres com abans.

— %2$s','Your membership at %s has been reinstated'=>'La teva pertinença a %s ha estat restablerta','Hi %1$s,

The %2$s community has opened a vote to remove a member. The vote closes on %3$s.

Cast your vote:

Vote YES (remove): %4$s

Vote NO (keep):    %5$s

A majority of active members (more than 50%%) must vote yes for the removal to proceed. You can change your vote by clicking the other link before the deadline.

— %2$s'=>'Hola %1$s,

La comunitat de %2$s ha obert una votació per eliminar un membre. La votació finalitza el %3$s.

Emet el teu vot:

Vota SÍ (eliminar): %4$s

Vota NO (mantenir):    %5$s

Una majoria dels membres actius (més del 50%%) ha de votar sí perquè l\'eliminació segueixi endavant. Pots canviar el teu vot fent clic a l\'altre enllaç abans del termini.

— %2$s','Community removal vote open at %s'=>'Votació d\'eliminació de la comunitat oberta a %s','Community removal vote passed at %s'=>'La votació d\'eliminació de la comunitat ha estat aprovada a %s','The community removal vote has closed with a majority in favor.

The artist\'s account and all published work have been permanently deleted from %1$s.

— %2$s'=>'La votació d\'eliminació de la comunitat s\'ha tancat amb una majoria a favor.

El compte de l\'artista i tota la feina publicada han estat eliminats permanentment de %1$s.

— %2$s','Community removal vote did not pass at %s'=>'La votació d\'eliminació de la comunitat no ha estat aprovada a %s','The community removal vote has closed. The required majority was not reached and the artist\'s membership remains active.

— %s'=>'La votació d\'eliminació de la comunitat s\'ha tancat. No s\'ha assolit la majoria requerida i la pertinença de l\'artista continua activa.

— %s','Please enter a valid email address.'=>'Introdueix una adreça electrònica vàlida.','wp_mail() reported a failure — check your site\'s outgoing mail configuration.'=>'wp_mail() ha informat d\'un error — comprova la configuració del correu sortint del teu lloc.','You\'re invited to join %s'=>'Estàs convidat a unir-te a %s','[TEST] %s'=>'[PROVA] %s','You\'re invited'=>'Estàs convidat','Apply to join'=>'Sol·licita unirte','No account needed to apply — the community reviews and votes on every application.'=>'No cal cap compte per sol·licitar-ho — la comunitat revisa i vota cada sol·licitud.','You are already an admitted Agnosis artist.'=>'Ja ets un artista admès d\'Agnosis.','Your name'=>'El teu nom','required'=>'obligatori','Email address'=>'Adreça electrònica','Short bio'=>'Breu biografia','A few sentences about your practice, medium, and background.'=>'Unes quantes frases sobre la teva pràctica, mitjà i trajectòria.','Portfolio URL'=>'URL del portafolis','Why do you want to join?'=>'Per què vols unir-te?','Language you work in'=>'Llengua en què treballes','Select your language'=>'Selecciona la teva llengua','Helps us communicate and translate content in your language.'=>'Ens ajuda a comunicar-nos i a traduir el contingut a la teva llengua.','Apply'=>'Sol·licita','Almost there — check your inbox for a confirmation email and click the link to open your application for community review.'=>'Ja gairebé hi ets — comprova la safata d\'entrada per trobar un correu de confirmació i fes clic a l\'enllaç per obrir la teva sol·licitud perquè la comunitat la revisi.','Please fill in all required fields.'=>'Si us plau, omple tots els camps obligatoris.','This preferences link is invalid or has been tampered with.'=>'Aquest enllaç de preferències no és vàlid o ha estat manipulat.','This preferences link is no longer valid for this account.'=>'Aquest enllaç de preferències ja no és vàlid per a aquest compte.','Notification preferences'=>'Preferències de notificacions','Mute community broadcast messages from other artists.'=>'Silencia els missatges de difusió de la comunitat d\'altres artistes.','Application vote emails'=>'Correus electrònics de votació de sol·licituds','Instantly, one email per application (default).'=>'Immediatament, un correu per sol·licitud (per defecte).','Once a day, a single digest of every application still awaiting my vote.'=>'Un cop al dia, un resum únic de totes les sol·licituds que encara esperen el meu vot.','Turn off the contact form on my page — visitors won\'t be able to message me.'=>'Desactiva el formulari de contacte de la meva pàgina — els visitants no podran enviar-me missatges.','Save preferences'=>'Desa les preferències','Community broadcasts are now muted.'=>'Els missatges de difusió de la comunitat ara estan silenciats.','You\'ll continue to receive community broadcasts.'=>'Continuaràs rebent els missatges de difusió de la comunitat.','You\'ll receive one daily digest of applications awaiting your vote.'=>'Rebràs un resum diari de les sol·licituds pendents del teu vot.','You\'ll receive an email as soon as each new application arrives.'=>'Rebràs un correu electrònic tan bon punt arribi cada nova sol·licitud.','The contact form on your page is now turned off.'=>'El formulari de contacte de la teva pàgina ara està desactivat.','Visitors can still reach you through the contact form on your page.'=>'Els visitants encara poden posar-se en contacte amb tu a través del formulari de contacte de la teva pàgina.','Preferences saved'=>'Preferències desades','Artworks'=>'Obres d\'art','Write about this artwork…'=>'Escriu sobre aquesta obra…','Biographies'=>'Biografies','Biography'=>'Biografia','Add New Biography'=>'Afegeix una biografia nova','Edit Biography'=>'Edita la biografia','New Biography'=>'Biografia nova','View Biography'=>'Mostra la biografia','Search Biographies'=>'Cerca biografies','No biographies found.'=>'No s\'han trobat biografies.','No biographies in trash.'=>'No hi ha biografies a la paperera.','All Biographies'=>'Totes les biografies','Events'=>'Esdeveniments','Event'=>'Esdeveniment','Add New Event'=>'Afegeix un esdeveniment nou','Edit Event'=>'Edita l\'esdeveniment','New Event'=>'Esdeveniment nou','View Event'=>'Mostra l\'esdeveniment','Search Events'=>'Cerca esdeveniments','No events found.'=>'No s\'han trobat esdeveniments.','No events in trash.'=>'No hi ha esdeveniments a la paperera.','All Events'=>'Tots els esdeveniments','Medium'=>'Mitjà','Mediums'=>'Mitjans','Search Mediums'=>'Cerca mitjans','All Mediums'=>'Tots els mitjans','Edit Medium'=>'Edita el mitjà','Update Medium'=>'Actualitza el mitjà','Add New Medium'=>'Afegeix un mitjà nou','New Medium Name'=>'Nom del mitjà nou','Artwork'=>'Obra','Add New'=>'Afegeix-ne un de nou','Add New Artwork'=>'Afegeix una obra nova','Edit Artwork'=>'Edita l\'obra','New Artwork'=>'Obra nova','View Artwork'=>'Mostra l\'obra','Search Artworks'=>'Cerca obres','No artworks found.'=>'No s\'han trobat obres.','No artworks in trash.'=>'No hi ha obres a la paperera.','All Artworks'=>'Totes les obres','Artwork Archives'=>'Arxius de l\'obra','Artwork Attributes'=>'Atributs de l\'obra','Invalid vote link.'=>'Enllaç de vot invàlid.','This vote link is invalid or has been tampered with.'=>'Aquest enllaç de vot no és vàlid o ha estat manipulat.','Voter account not found.'=>'No s\'ha trobat el compte del votant.','Vote to remove this artist from the community?'=>'Votar per retirar aquest artista de la comunitat?','Vote to keep this artist in the community?'=>'Votar per mantenir aquest artista a la comunitat?','Your vote will be recorded once you confirm below.'=>'El teu vot es registrarà un cop ho confirmis a continuació.','Confirm my vote'=>'Confirma el meu vot','You voted to remove this artist from the community.'=>'Has votat per eliminar aquest artista de la comunitat.','You voted to keep this artist in the community.'=>'Has votat per mantenir aquest artista a la comunitat.','%d vote to remove recorded so far.'=>'S\'ha registrat %d vot per eliminar fins ara.' . "\0" . 'S\'han registrat %d vots per eliminar fins ara.','Vote recorded'=>'Vot registrat','Vote error'=>'Error de votació','%d application awaiting your vote'=>'%d sol·licitud pendent del teu vot' . "\0" . '%d sol·licituds pendents del teu vot','Here\'s your daily digest of applications to %1$s still awaiting your vote. Each has a %2$d-day voting window from when it was confirmed.'=>'Aquí tens el teu resum diari de les sol·licituds a %1$s que encara esperen el teu vot. Cadascuna té una finestra de votació de %2$d dies des que es va confirmar.','Prefer these one at a time again? You can switch back any time from your notification preferences link below.'=>'Prefereixes tornar a rebre-les d\'una en una? Pots tornar a canviar-ho en qualsevol moment des de l\'enllaç de preferències de notificacions de més avall.','Vote in favor of this application?'=>'Votar a favor d\'aquesta sol·licitud?','Vote against this application?'=>'Votar en contra d\'aquesta sol·licitud?','You voted in favor of this application.'=>'Has votat a favor d\'aquesta sol·licitud.','You voted against this application.'=>'Has votat en contra d\'aquesta sol·licitud.','%d positive vote recorded so far.'=>'S\'ha registrat %d vot positiu fins ara.' . "\0" . 'S\'han registrat %d vots positius fins ara.','is active and configured for'=>'està actiu i configurat per a','Subdomain'=>'Subdomini','routing mode'=>'mode d\'encaminament','This conflicts with Agnosis artist subdomains — both plugins would claim the same subdomain namespace.'=>'Això entra en conflicte amb els subdominis d\'artista d\'Agnosis: tots dos connectors reclamarien el mateix espai de noms de subdomini.','Artist subdomain routing is'=>'L\'encaminament de subdomini d\'artista és','completely inactive'=>'completament inactiu','until this is resolved.'=>'fins que això es resolgui.','Fix: open'=>'Solució: obre','Settings'=>'Configuració','Language Router'=>'Language Router','and switch the URL strategy to'=>'i canvia l\'estratègia d\'URL a','Path prefix (subfolder)'=>'Prefix de ruta (subcarpeta)','This is the LinguaForge default and allows artist subdomains to coexist with language subfolders'=>'Aquesta és la configuració predeterminada de LinguaForge i permet que els subdominis d\'artista coexisteixin amb subcarpetes d\'idioma','Agnosis — Artist Subdomain Routing is disabled'=>'Agnosis — l\'encaminament de subdomini d\'artista està desactivat','Open LinguaForge Settings'=>'Obre la configuració de LinguaForge','Agnosis Artist'=>'Artista d\'Agnosis','My Submissions'=>'Les meves trameses','Join'=>'Uneix-te','Send new artwork to be published.'=>'Envia una obra nova per publicar-la.','Update your artist biography.'=>'Actualitza la teva biografia d\'artista.','Announce an upcoming event.'=>'Anuncia un esdeveniment proper.','Replace'=>'Reemplaça','Send a new version of an existing artwork — subject must match its title.'=>'Envia una nova versió d\'una obra existent — l\'assumpte ha de coincidir amb el títol.','Request an existing artwork or event be taken down — subject must match its title.'=>'Sol·licita que es retiri una obra o un esdeveniment existent — l\'assumpte ha de coincidir amb el títol.','Promote'=>'Promociona','Choose which artwork represents you in the shared community gallery on the main site — subject must match its title. Your own subdomain already shows everything you\'ve published.'=>'Tria quina obra et representa a la galeria comunitària compartida del lloc principal — l\'assumpte ha de coincidir amb el títol. El teu propi subdomini ja mostra tot el que has publicat.','Photo-only'=>'Només foto','Publish a photo exactly as sent — no AI enhancement, no quality check.'=>'Publica una foto exactament tal com s\'ha enviat — sense millora amb IA, sense revisió de qualitat.','Pure'=>'Pura','Publish exactly as sent — no AI at all, not even the title/description pass.'=>'Publica exactament tal com s\'ha enviat — sense cap IA, ni tan sols la passada de títol/descripció.','Send a message to every other artist in the community.'=>'Envia un missatge a tots els altres artistes de la comunitat.','Spotted something to fix after publishing? Log in and look for the pencil icon on your published page — you can correct the title, text, or photo yourself, no need to email us again.'=>'Has vist alguna cosa per corregir després de publicar? Inicia sessió i busca la icona del llapis a la teva pàgina publicada — pots corregir tu mateix el títol, el text o la foto, sense necessitat d\'enviar-nos un altre correu electrònic.','Manage notification preferences: %s'=>'Gestiona les preferències de notificacions: %s','Manage notification preferences'=>'Gestiona les preferències de notificacions','Agnosis Membership Application'=>'Sol·licitud de pertinença a Agnosis','Agnosis Governance Participation'=>'Participació en la governança d’Agnosis','Agnosis Newsletter Subscription'=>'Subscripció al butlletí d’Agnosis','Agnosis Newsletter Delivery History'=>'Historial d’entrega del butlletí d’Agnosis','Agnosis Contact Messages Sent'=>'Missatges de contacte d’Agnosis enviats','Agnosis Transactions'=>'Transaccions d’Agnosis','Agnosis Notification Preferences'=>'Preferències de notificació d’Agnosis','Display name'=>'Nom visible','Application statement'=>'Declaració de la sol·licitud','Language'=>'Idioma','Applied at'=>'Sol·licitada el','Resolved at'=>'Resolta el','Type'=>'Tipus','Community vouch given'=>'Avaluació de la comunitat concedida','Date'=>'Data','Admission vouch given'=>'Avaluació d’admissió concedida','Community removal vote'=>'Vot de retirada de la comunitat','Vote'=>'Vot','Community size-cap vote'=>'Vot del límit de mida de la comunitat','Locale'=>'Local','Subscribed at'=>'Subscrit el','Confirmed at'=>'Confirmat el','Unsubscribed at'=>'Donat de baixa el','Issue'=>'Incidència','Recipient type'=>'Tipus de destinatari','Queued at'=>'En cua el','Sent to artist'=>'Enviat a l’artista','Translated message'=>'Missatge traduït','Rejection reason'=>'Motiu del rebuig','IP address'=>'Adreça IP','Sent at'=>'Enviat el','Amount'=>'Import','Currency'=>'Moneda','Fee'=>'Comissió','Gateway'=>'Passarel·la','Your membership application/account is still active. To remove this data, use the "leave the network" link from any Agnosis email, or ask an administrator.'=>'La teva sol·licitud de pertinença/compte encara és activa. Per eliminar aquestes dades, fes servir l’enllaç "deixar la xarxa" de qualsevol correu electrònic d’Agnosis, o demana-ho a un administrador.','Your biography, statement, and portfolio link were erased. Your email address was kept on file — your account is currently banned, and it\'s the only way this site can continue to enforce that.'=>'La teva biografia, declaració i l’enllaç del teu portafolis s’han esborrat. La teva adreça electrònica s’ha conservat — el teu compte està actualment blocat, i és l’única manera que aquest lloc pot continuar aplicant-ho.','[message removed]'=>'[missatge eliminat]','Vouch messages you wrote were redacted. Governance votes you cast were kept as-is — a vote is a community record, not personal data, and removing it would silently change a settled decision.'=>'Els missatges d’avals que vas escriure s’han censurat. Els vots de governança que vas emetre s’han conservat tal com eren — un vot és un registre de la comunitat, no una dada personal, i eliminar-lo canviaria silenciosament una decisió ja presa.','Past newsletter delivery records were anonymized; per-issue delivery counts were kept for statistics.'=>'Els registres antics d’entrega del butlletí s’han anonimitzat; els recomptes d’entregues per número s’han conservat per a les estadístiques.','Transaction (donation/sale) records were kept in full — financial records are subject to a legal retention obligation and are exempt from erasure under GDPR Art. 17(3)(b).'=>'Els registres de transaccions (donació/venda) s’han conservat íntegrament — els registres financers estan subjectes a una obligació legal de conservació i estan exempts de supressió segons l’art. 17(3)(b) del RGPD.','Agnosis is a federated art-publishing plugin. The following is a starting point for describing what it collects — review and adapt it to your site\'s actual configuration before publishing.'=>'Agnosis és un connector federat de publicació artística. El text següent és un punt de partida per descriure què recull — revisa’l i adapta’l a la configuració real del teu lloc abans de publicar-lo.','What personal data we collect and why'=>'Quines dades personals recopilem i per què','When you apply to join, we store your email address, display name, biography, statement, and portfolio link to run the community vouching process. When you email us artwork, a biography, or an event, the content of that email (including your address) is stored while it is processed and reviewed. When you subscribe to our newsletter or message an artist through their contact form, we store your email address (and, for contact messages, your IP address) to deliver that message or send you future issues.'=>'Quan et presentes per unir-te, emmagatzemem la teva adreça electrònica, nom visible, biografia, declaració i enllaç del portafolis per gestionar el procés d’avals de la comunitat. Quan ens envies obres, una biografia o un esdeveniment per correu electrònic, el contingut d’aquest correu (inclosa la teva adreça) s’emmagatzema mentre es processa i es revisa. Quan et subscrius al nostre butlletí o envies un missatge a un artista a través del seu formulari de contacte, emmagatzemem la teva adreça electrònica (i, en el cas dels missatges de contacte, també la teva adreça IP) per lliurar aquest missatge o enviar-te futurs números.','Who we share it with'=>'Amb qui ho compartim','Submitted artwork descriptions and images may be sent to a third-party AI provider (OpenAI, Anthropic, or Stability AI, depending on this site\'s configuration) to help write publication text and enhance images. Approved posts are also broadcast publicly over ActivityPub (the Fediverse) as part of this plugin\'s core federation feature.'=>'Les descripcions i imatges d’obres enviades es poden enviar a un proveïdor extern d’IA (OpenAI, Anthropic o Stability AI, segons la configuració d’aquest lloc) per ajudar a redactar el text de publicació i millorar les imatges. Les publicacions aprovades també es transmeten públicament per ActivityPub (el Fediverse) com a part de la funció bàsica de federació d’aquest connector.','How long we retain your data'=>'Durant quant de temps conservem les teves dades','Retention varies by data type; see this site\'s administrator for specifics. You can request a copy of, or the erasure of, the personal data described above at any time using this site\'s standard WordPress data request tools.'=>'La conservació varia segons el tipus de dada; consulta’n els detalls amb l’administrador d’aquest lloc. Pots sol·licitar en qualsevol moment una còpia o l’esborrat de les dades personals descrites més amunt mitjançant les eines estàndard de WordPress per a sol·licituds de dades d’aquest lloc.','Submitted text and images may be processed by a third-party AI provider. Approved posts are published publicly and shared across the Fediverse — this cannot be fully undone later.'=>'El text i les imatges enviats es poden processar mitjançant un proveïdor extern d’IA. Les publicacions aprovades es publiquen públicament i es comparteixen a tot el Fediverse — això no es pot desfer completament després.','Your message may be reviewed by an automated content filter before being sent to the artist.'=>'El teu missatge pot ser revisat per un filtre automàtic de contingut abans d’enviar-se a l’artista.','See our %s for details.'=>'Consulteu la nostra %s per obtenir més detalls.','Privacy Policy'=>'Política de privadesa','Too many requests. Please wait %d seconds and try again.'=>'Hi ha massa sol·licituds. Espereu %d segons i torneu-ho a provar.','Submission limit reached. Please wait before sending again.'=>'S\'ha arribat al límit d\'enviaments. Espereu abans de tornar a enviar.','Please complete the verification check and try again.'=>'Completeu la comprovació de verificació i torneu-ho a provar.','Could not verify you\'re human right now. Please try again in a moment.'=>'No s\'ha pogut verificar que sou una persona en aquest moment. Torneu-ho a provar d\'aquí a una estona.','Verification failed. Please try again.'=>'La verificació ha fallat. Torneu-ho a provar.','View Agnosis details'=>'Artista d\'Agnosis','View details'=>'Mostra l\'esdeveniment','Every 5 minutes'=>'Cada 5 minuts','IMAP credentials are not configured.'=>'Les credencials IMAP no estan configurades.','Connected successfully. %1$d message(s) in inbox, %2$d unseen.'=>'S\'ha connectat correctament. %1$d missatge(s) a la safata d\'entrada, %2$d sense llegir.','Webhook secret not configured.'=>'El secret del webhook no està configurat.','Invalid or missing webhook signature.'=>'La signatura del webhook no és vàlida o falta.','Webhook request timestamp is missing, malformed, or too old.'=>'La marca de temps de la sol·licitud del webhook falta, té un format incorrecte o és massa antiga.','This webhook request has already been processed.'=>'Aquesta sol·licitud de webhook ja s\'ha processat.','OpenSSL is required for HTTP Signature verification.'=>'Cal OpenSSL per a la verificació de la signatura HTTP.','Signature header is required.'=>'Cal la capçalera de signatura.','Signature header is missing required fields (keyId, headers, signature).'=>'A la capçalera de signatura falten camps obligatoris (keyId, headers, signature).','Request date is too old or too far in the future.'=>'La data de la sol·licitud és massa antiga o és massa lluny en el futur.','Signature value is not valid base64.'=>'El valor de la signatura no és un base64 vàlid.','HTTP Signature verification failed.'=>'La verificació de la signatura HTTP ha fallat.','Digest header does not match the request body.'=>'La capçalera Digest no coincideix amb el cos de la sol·licitud.','keyId in Signature header is not a valid URL.'=>'keyId a la capçalera de signatura no és una URL vàlida.','Failed to fetch actor document.'=>'No s\'ha pogut obtenir el document de l\'actor.','Actor document returned a non-200 response.'=>'El document de l\'actor ha retornat una resposta que no és 200.','Actor document does not contain a publicKey.publicKeyPem field.'=>'El document de l\'actor no conté un camp publicKey.publicKeyPem.','Node URL is required.'=>'L\'URL del node és necessària.','Contact %s'=>'Contacteu amb %s','Contact this artist'=>'Poseu-vos en contacte amb aquest artista','Get in touch with %s'=>'Poseu-vos en contacte amb %s','Get in touch'=>'Poseu-vos en contacte','This newsletter issue could not be found.'=>'No s\'ha pogut trobar aquest número del butlletí.','Issue not found'=>'Número no trobat','Newsletter archive'=>'Arxiu del butlletí','Past issues of the %s newsletter.'=>'Números anteriors del butlletí de %s.','No issues have gone out yet — check back soon.'=>'Encara no s\'ha publicat cap número — torneu-ho a comprovar aviat.','← Newer'=>'← Més nous','Older →'=>'Més antics →','Newsletter archive — %s'=>'Arxiu del butlletí — %s','%1$s Newsletter — %2$s'=>'Butlletí de %1$s — %2$s','%s Newsletter'=>'Butlletí de %s','Nothing new to report this time — but the community is still here, and the next issue will have more.'=>'No hi ha res de nou per informar aquest cop — però la comunitat continua aquí, i el proper número tindrà més contingut.','New artwork'=>'Nova obra','Upcoming events'=>'Esdeveniments propers','%d new artwork published'=>'S\'han publicat %d obra nova' . "\0" . 'S\'han publicat %d obres noves','%d new event announced'=>'S\'ha anunciat %d esdeveniment nou' . "\0" . 'S\'han anunciat %d esdeveniments nous','Welcome to our newest member: %s'=>'Benvingut/da al nostre membre més recent: %s' . "\0" . 'Benvinguts/des als nostres membres més recents: %s','%d community vote is open — check your email for your personal voting link.'=>'Hi ha oberta %d votació de la comunitat — comproveu el vostre correu electrònic per trobar l\'enllaç de votació personal.' . "\0" . 'Hi ha %d vots de la comunitat oberts — comprova el teu correu electrònic per als teus enllaços de votació personals.','Recent work from the community'=>'Treballs recents de la comunitat','…and %d more.'=>'…i %d més.' . "\0" . '…i %d més.','Community Newsletter'=>'Butlletí de la comunitat','Having trouble viewing this email?'=>'Tens problemes per veure aquest correu electrònic?','View it online.'=>'Consulta\'l en línia.','Unsubscribe'=>'Cancel·la la subscripció','Subscribe to get these by email'=>'Subscriu-te per rebre\'ls per correu electrònic','[%s] Community newsletter'=>'[%s] Butlletí de la comunitat','[%s] Newsletter'=>'[%s] Butlletí','Get new artworks, artist admissions, and community updates in your inbox.'=>'Rep noves obres, admissions d\'artistes i actualitzacions de la comunitat a la teva safata d\'entrada.','Subscribe to the newsletter'=>'Subscriu-te al butlletí','Unknown newsletter type.'=>'Tipus de butlletí desconegut.','A previous issue is still sending — please wait for it to finish.'=>'Encara s\'està enviant un número anterior — espera que acabi.','Please enter a valid email address to send the test to.'=>'Introdueix una adreça electrònica vàlida per enviar-hi la prova.','This is a TEST send — it previews the next issue using the current draft intro and recent activity. It was not counted as a real send and no subscribers were emailed. The unsubscribe link below is a non-functional placeholder.'=>'Aquest és un enviament de PROVA — previsualitza el proper número amb la introducció provisional actual i l\'activitat recent. No s\'ha comptat com un enviament real i no s\'ha enviat cap correu als subscriptors. L\'enllaç de cancel·lació de subscripció de sota és un text de reserva sense funcionalitat.','The %1$s at %2$s is due to send in about a day. Agnosis drafted an intro from what\'s new since the last issue:'=>'El %1$s de %2$s s\'ha d\'enviar d\'aquí a aproximadament un dia. Agnosis ha redactat una introducció a partir del que hi ha de nou des de l\'últim número:','It\'s already saved and will be used as-is if you don\'t act — review it, rewrite it, or clear it back to blank here:'=>'Ja està desat i s\'utilitzarà tal qual si no hi fas res — revisa\'l, reescriu-lo o torna\'l a deixar en blanc aquí:','%1$s intro drafted for %2$s — review before it sends'=>'Introducció redactada per a %1$s de %2$s — revisa-la abans que s\'enviï','Subscribe'=>'Subscriu-te','See past issues'=>'Veure números anteriors','Almost there — check your inbox for a confirmation link.'=>'Ja gairebé ho tens — comprova la safata d\'entrada per a un enllaç de confirmació.','[%s] Confirm your newsletter subscription'=>'[%s] Confirma la subscripció al butlletí','Thanks for signing up! Confirm your email address to start receiving the newsletter.'=>'Gràcies per registrar-te! Confirma la teva adreça electrònica per començar a rebre el butlletí.','Confirm subscription'=>'Confirma la subscripció','If you didn\'t request this, simply ignore this email — you will not be subscribed.'=>'Si no ho has sol·licitat, simplement ignora aquest correu — no se\'t subscriurà.','Artists are automatically subscribed — there is nothing to confirm.'=>'Els artistes se subscriuen automàticament — no cal confirmar res.','Subscription confirmed'=>'Subscripció confirmada','You\'re all set — the newsletter will land in your inbox from now on.'=>'Ja està tot a punt — el butlletí arribarà a la teva safata d\'entrada a partir d\'ara.','Unsubscribed'=>'Cancel·lació de subscripció completada','You will no longer receive the newsletter. Sorry to see you go.'=>'Ja no rebràs el butlletí. Lamentem que marxis.','This unsubscribe link is invalid or has already been used.'=>'Aquest enllaç de cancel·lació de subscripció no és vàlid o ja s\'ha utilitzat.','This unsubscribe link is invalid or has been tampered with.'=>'Aquest enllaç de cancel·lació de subscripció no és vàlid o ha estat manipulat.','Account not found.'=>'No s\'ha trobat el compte.','You will no longer receive the artist newsletter. You can re-subscribe any time from your submissions page.'=>'Ja no rebràs el butlletí d\'artista. Pots tornar-te a subscriure en qualsevol moment des de la teva pàgina d\'enviaments.','Confirm your subscription?'=>'Confirmes la teva subscripció?','You\'ll start receiving the newsletter once you confirm below.'=>'Començaràs a rebre el butlletí un cop ho confirmis a continuació.','Unsubscribe from the newsletter?'=>'Cancel·lar la subscripció al butlletí?','You will stop receiving the newsletter once you confirm below.'=>'Deixaràs de rebre el butlletí un cop ho confirmis a continuació.','Confirm unsubscribe'=>'Confirma la cancel·lació de la subscripció','That doesn\'t look like a valid web address.'=>'Això no sembla una adreça web vàlida.','This site isn\'t on this Agnosis node\'s list of trusted platforms, and automatic link review is turned off here.'=>'Aquest lloc no és a la llista de plataformes de confiança d\'aquest node d\'Agnosis, i la revisió automàtica d\'enllaços està desactivada aquí.','This node couldn\'t safely load that page to review it (it may be unreachable, or blocked for security reasons).'=>'Aquest node no ha pogut carregar aquesta pàgina de manera segura per revisar-la (pot ser que no sigui accessible o que estigui bloquejada per motius de seguretat).','Automatic review of that page\'s content was inconclusive.'=>'La revisió automàtica del contingut d\'aquesta pàgina no ha estat concloent.','Automatic review found that page\'s content isn\'t allowed to be embedded on this site.'=>'La revisió automàtica ha detectat que el contingut d\'aquesta pàgina no es pot incrustar en aquest lloc.','Gallery overview'=>'Visió general de la galeria','Feature this artwork in the gallery overview'=>'Destaca aquesta obra a la visió general de la galeria','Featured artworks are always chosen first when selecting one work per artist for the homepage overview.'=>'Les obres destacades sempre es trien primer quan se selecciona una obra per artista per a la visió general de la pàgina d\'inici.','[Agnosis] Confirm removal of: %s'=>'[Agnosis] Confirma l\'eliminació de: %s','[%s] We couldn\'t find that artwork or event'=>'[%s] No hem pogut trobar aquesta obra o esdeveniment','[%s] Your artwork is now featured'=>'[%s] La teva obra ara està destacada','[%s] We couldn\'t find that artwork'=>'[%s] No hem pogut trobar aquesta obra','We received a removal request for "%s", but couldn\'t find an artwork or event with that exact title in your account.'=>'Hem rebut una sol·licitud per eliminar "%s", però no hem pogut trobar cap obra o esdeveniment amb aquest títol exacte al teu compte.','We received a request to feature "%s", but couldn\'t find a published artwork with that exact title in your account.'=>'Hem rebut una sol·licitud per destacar "%s", però no hem pogut trobar cap obra publicada amb aquest títol exacte al teu compte.','Did you mean "%s"?'=>'Volies dir "%s"?','Yes, remove this instead'=>'Sí, elimina això en lloc d’això','Or simply resend your original email with that exact title.'=>'O simplement torna a enviar el teu correu original amb aquest títol exacte.','Resend your original email with that exact title.'=>'Torna a enviar el teu correu original amb aquest títol exacte.','Your current titles:'=>'Els teus títols actuals:','Titles are matched exactly, so a small difference in wording is enough to miss — double-check spelling, capitalization, and punctuation against the list above before resending.'=>'Els títols han de coincidir exactament, així que una petita diferència en la redacció ja és suficient per no trobar-los — comprova bé l’ortografia, les majúscules i la puntuació amb la llista de dalt abans de tornar a enviar-lo.','"%s" is now your featured artwork on the gallery overview.'=>'"%s" és ara la teva obra destacada a la vista general de la galeria.','Any previously featured artwork has been unfeatured automatically — only one piece is featured at a time.'=>'Qualsevol obra destacada anterior s’ha deixat de destacar automàticament — només una peça pot estar destacada alhora.','[Agnosis] Your submission is ready to review: %s'=>'[Agnosis] La teva tramesa ja està a punt per revisar: %s','event'=>'esdeveniment','artwork'=>'obra','We received a removal request for the following %s:'=>'Hem rebut una sol·licitud d’eliminació per al/la següent %s:','If you want to permanently remove this %s, click the button below. This action cannot be undone.'=>'Si vols eliminar permanentment aquest/a %s, fes clic al botó de sota. Aquesta acció no es pot desfer.','Yes, remove this %s'=>'Sí, elimina aquest/a %s','If you did not request this removal, simply ignore this email — your %s will remain published.'=>'Si no vas sol·licitar aquesta eliminació, simplement ignora aquest correu — el/la teu/teva %s es mantindrà publicat/da.','This confirmation link expires in 7 days.'=>'Aquest enllaç de confirmació caduca en 7 dies.','If you did not request this removal, simply ignore this email — nothing will be removed unless you click one of the buttons above.'=>'Si no vas sol·licitar aquesta eliminació, simplement ignora aquest correu — el/la teu/teva %s es mantindrà publicat/da.','These confirmation links expire in 7 days.'=>'Aquest enllaç de confirmació caduca en 7 dies.','📷 Photo enhanced automatically'=>'📷 Foto millorada automàticament','We detected some photographic issues and applied AI correction to improve visibility of your artwork:'=>'Hem detectat alguns problemes fotogràfics i hem aplicat una correcció amb IA per millorar la visibilitat de la teva obra:','The artwork itself has not been altered — only the photograph quality was corrected.'=>'La mateixa obra no s’ha alterat — només s’ha corregit la qualitat de la fotografia.','📷 Photo quality score: %d/10'=>'📷 Puntuació de qualitat de la foto: %d/10','Double-check the link is correct — you can fix or remove it in the form below before publishing.'=>'Revisa que l’enllaç sigui correcte — el pots corregir o eliminar al formulari de sota abans de publicar-lo.','If the link was correct, its destination may simply not be from a source this site automatically embeds.'=>'Si l’enllaç era correcte, potser la destinació simplement no prové d’una font que aquest lloc insereixi automàticament.','🔗 A link was not included'=>'🔗 No s’ha inclòs cap enllaç' . "\0" . '🔗 No s’han inclòs alguns enllaços','The following couldn\'t be automatically embedded, so they were left out:'=>'No s’han pogut incrustar automàticament els següents, així que s’han omès:','Its subject line didn\'t exactly match one of your existing titles. If you meant to update an existing event, "%s", resend your email with that exact title instead.'=>'L’assumpte no coincidia exactament amb cap dels teus títols existents. Si volies actualitzar un esdeveniment existent, "%s", torna a enviar el correu amb aquest títol exacte.','Its subject line didn\'t exactly match one of your existing titles. If you meant to replace an existing artwork, "%s", resend your email with that exact title instead.'=>'L’assumpte no coincidia exactament amb cap dels teus títols existents. Si volies substituir una obra existent, "%s", torna a enviar el correu amb aquest títol exacte.','📄 This was published as a new post'=>'📄 Això s’ha publicat com una entrada nova','Your submission has been processed. Here\'s what our AI curator came up with — take a look and let us know if it\'s ready to publish.'=>'La teva tramesa s’ha processat. Aquí tens el que ha creat el nostre curador amb IA — fes-hi un cop d’ull i digues-nos si està a punt per publicar-se.','On the site: %s'=>'Al lloc: %s','In your language: %s'=>'En la teva llengua: %s','Looks great — Publish it'=>'Sembla bé — publica-ho','Discard'=>'Descarta','Want to tweak the title, text or tags before publishing?'=>'Vols ajustar el títol, el text o les etiquetes abans de publicar?','Open your submissions page →'=>'Obre la teva pàgina de trameses →','The Publish and Discard links above expire in %d day. Your submission stays as a draft until you decide.'=>'Els enllaços de Publica i Descarta de dalt caduquen en %d dia. La teva tramesa es manté com a esborrany fins que decideixis.' . "\0" . 'Els enllaços de Publica i Descarta de dalt caduquen en %d dies. La teva tramesa es manté com a esborrany fins que decideixis.','[%s] We couldn\'t process your submission'=>'[%s] No hem pogut processar la teva tramesa','[%s] We couldn\'t find a photo in your email'=>'[%s] No hem pogut trobar cap foto al teu correu','We received your email, but couldn\'t process a usable photo, audio, or video file from it — so nothing was published. This can happen when an image is pasted or inserted inline rather than added as a proper attachment, or when a file arrives in a format this server can\'t convert (for example, an iPhone photo saved in HEIC/HEIF format).'=>'Hem rebut el teu correu, però no n’hem pogut processar cap fitxer de foto, àudio o vídeo usable — així que no s’ha publicat res. Això pot passar quan s’enganxa o s’insereix una imatge en línia en lloc d’afegir-la com a adjunt correcte, o quan un fitxer arriba en un format que aquest servidor no pot convertir (per exemple, una foto d’iPhone guardada en format HEIC/HEIF).','To resend correctly:'=>'Per tornar-lo a enviar correctament:','Use your mail app\'s "Attach file" (usually a paperclip icon) rather than "Insert photo" or pasting the image directly into the message body.'=>'Fes servir l’opció "Adjunta fitxer" de la teva aplicació de correu (normalment una icona de clip) en lloc de "Insereix foto" o d’enganxar la imatge directament al cos del missatge.','If your photo was taken on an iPhone, try switching Settings → Camera → Formats to "Most Compatible" before taking or sending it, or use "Options" in Mail to send it as a JPEG.'=>'Si la teva foto s’ha fet amb un iPhone, prova de canviar Configuració → Càmera → Formats a "Més compatible" abans de fer-la o enviar-la, o fes servir "Opcions" al Mail per enviar-la com a JPEG.','Supported formats: JPEG, PNG, WebP, GIF, TIFF, or HEIC/HEIF for images; MP3, WAV, M4A, OGG, or FLAC for audio; MP4, MOV, AVI, WebM, OGG, or MPEG for video.'=>'Formats compatibles: JPEG, PNG, WebP, GIF, TIFF o HEIC/HEIF per a imatges; MP3, WAV, M4A, OGG o FLAC per a àudio; MP4, MOV, AVI, WebM, OGG o MPEG per a vídeo.','Once it\'s properly attached, just send it to the same address again — we\'ll pick it up automatically.'=>'Un cop estigui ben adjunt, només cal que l’enviïs de nou a la mateixa adreça — el recollirem automàticament.','[%s] We couldn\'t process that email'=>'[%s] No hem pogut processar la teva tramesa','Once it\'s a fresh, original message, just send it to the same address again — we\'ll pick it up automatically.'=>'Un cop estigui ben adjunt, només cal que l’enviïs de nou a la mateixa adreça — el recollirem automàticament.','The photo is too dark to show your artwork clearly. Try photographing near a large window in daylight, or use a soft lamp aimed at the work from the side.'=>'La foto és massa fosca per mostrar la teva obra amb claredat. Prova de fotografiar-la prop d\'una finestra gran amb llum de dia, o bé usa un llum suau dirigit a l\'obra des del costat.','The photo is underexposed (too dark). Try photographing near a large window in daylight, or use a soft lamp aimed at the work from the side.'=>'La foto està subexposada (massa fosca). Prova de fotografiar-la prop d\'una finestra gran amb llum de dia, o bé usa un llum suau dirigit a l\'obra des del costat.','The photo is overexposed (too bright / washed out). Avoid direct sunlight or flash pointed straight at the artwork — diffuse or indirect light works best.'=>'La foto està sobreexposada (massa brillant / rentada). Evita la llum solar directa o el flaix apuntat directament cap a l\'obra — la llum difusa o indirecta funciona millor.','The photo is too bright or washed out. Avoid direct sunlight or flash — diffuse light or shade gives more even tones.'=>'La foto és massa brillant o està rentada. Evita la llum solar directa o el flaix — la llum difusa o l\'ombra donen tons més uniformes.','There is glare or a bright reflection on the artwork. Tilt the canvas slightly or photograph at an angle to eliminate reflections from the surface.'=>'Hi ha brillantor o un reflex intens sobre l\'obra. Inclina lleugerament la tela o fes la foto des d\'un angle per eliminar els reflexos de la superfície.','There is a reflection on the artwork surface. Tilt the canvas slightly or change your angle to eliminate it.'=>'Hi ha un reflex a la superfície de l\'obra. Inclina lleugerament la tela o canvia l\'angle per eliminar-lo.','The image is blurry. Rest your phone or camera on a stable surface, use the self-timer, and make sure the artwork fills most of the frame so autofocus locks on it.'=>'La imatge és borrosa. Recolza el mòbil o la càmera en una superfície estable, fes servir l\'autotemporitzador i assegura\'t que l\'obra ocupi la major part del marc perquè l\'enfoc automàtic s\'hi fixi.','The image is out of focus. Tap on the artwork on your phone screen before shooting to make sure autofocus locks on it, and hold the camera still.'=>'La imatge està desenfocada. Toca l\'obra a la pantalla del mòbil abans de fer la foto per assegurar-te que l\'enfoc automàtic s\'hi fixi, i mantén la càmera quieta.','There is motion blur. Hold the camera very still or use a tripod; press the shutter gently or use the self-timer to avoid shake.'=>'Hi ha desenfocament per moviment. Mantén la càmera ben quieta o fes servir un trípode; prem l\'obturador suaument o usa l\'autotemporitzador per evitar sacsejades.','Camera shake is visible. Use a tripod or rest the camera on a flat surface and use the self-timer to avoid movement when pressing the shutter.'=>'Es veu moviment de la càmera. Fes servir un trípode o recolza la càmera en una superfície plana i usa l\'autotemporitzador per evitar moviment en prémer l\'obturador.','The image resolution is too low. Use your phone\'s highest quality setting and make sure you\'re close enough that the artwork fills the frame.'=>'La resolució de la imatge és massa baixa. Fes servir la configuració de màxima qualitat del teu mòbil i assegura\'t d\'estar prou a prop perquè l\'obra ocupi el marc.','The image resolution is too low. Use your phone\'s highest quality setting and fill the frame with the artwork.'=>'La resolució de la imatge és massa baixa. Fes servir la configuració de màxima qualitat del teu mòbil i omple el marc amb l\'obra.','The image is pixelated. Shoot from closer or use a higher resolution setting on your camera.'=>'La imatge està pixelada. Fes la foto des de més a prop o usa una configuració de resolució més alta a la càmera.','The photo has a strong color cast. Shoot under neutral daylight or use your phone\'s Auto White Balance setting for more accurate colors.'=>'La foto té una forta dominància de color. Fes la foto amb llum natural neutra o usa la configuració d\'Auto White Balance del teu mòbil per obtenir colors més precisos.','The photo looks too yellow or warm. Shoot under natural daylight or switch your phone\'s white balance to Daylight / Cloudy.'=>'La foto té un to massa groc o càlid. Fes la foto amb llum natural o canvia el balanç de blancs del teu mòbil a Daylight / Cloudy.','The photo has a cold blue tint. Move the artwork to a warmer, more natural light source or adjust your camera\'s white balance.'=>'La foto té un to blau fred. Mou l\'obra a una font de llum més càlida i natural o ajusta el balanç de blancs de la càmera.','Part of the artwork appears to be cropped out of the frame. Step back and make sure the entire work is visible before shooting.'=>'Part de l\'obra sembla haver quedat tallada fora del marc. Fes un pas enrere i assegura\'t que tota l\'obra sigui visible abans de fer la foto.','The artwork is photographed at an angle, causing distortion. Shoot straight on, with the camera parallel to the canvas.'=>'L\'obra està fotografiada en angle, cosa que causa distorsió. Fes la foto de front, amb la càmera paral·lela a la tela.','The artwork looks distorted or skewed. Position your camera directly in front of the artwork, parallel to its surface.'=>'L\'obra es veu distorsionada o deformada. Col·loca la càmera directament davant de l\'obra, paral·lela a la seva superfície.','There is a shadow across part of the artwork. Reposition your light source or move the artwork so no shadows fall on the surface.'=>'Hi ha una ombra que travessa part de l\'obra. Reubica la font de llum o mou l\'obra perquè no hi caiguin ombres sobre la superfície.','We received your submission, but unfortunately the photo quality is too low for us to show your artwork clearly. We didn\'t publish it — but please don\'t be discouraged! A simple retake is usually all it takes.'=>'Hem rebut la teva tramesa, però malauradament la qualitat de la foto és massa baixa perquè puguem mostrar la teva obra amb claredat. No l\'hem publicat — però no et desanimis! Normalment, només cal tornar-la a fer.','📷 Photo quality score: %d / 10'=>'📷 Puntuació de qualitat de la foto: %d / 10','Here\'s what our AI detected and how to fix it:'=>'Això és el que ha detectat la nostra IA i com ho pots solucionar:','The overall photo quality was too low for our AI to process the artwork clearly.'=>'La qualitat global de la foto era massa baixa perquè la nostra IA pogués processar l\'obra amb claredat.','💡 Quick tips for a great artwork photo'=>'💡 Consells ràpids per a una bona foto de l\'obra','Use natural light — position the artwork near a window on a cloudy day for even, soft light.'=>'Fes servir llum natural — situa l\'obra prop d\'una finestra en un dia ennuvolat per obtenir una llum suau i uniforme.','Shoot straight on — hold your phone parallel to the canvas to avoid perspective distortion.'=>'Fes la foto de front — mantén el mòbil paral·lel a la tela per evitar la distorsió de perspectiva.','Fill the frame — let the artwork take up most of the shot; crop out distracting backgrounds.'=>'Omple el marc — fes que l\'obra ocupi la major part de la presa; retalla els fons que distreguin.','Hold still — tap the artwork on your screen to focus, then press the shutter gently or use a self-timer.'=>'Mantén-te quiet — toca l\'obra a la pantalla per enfocar, després prem l\'obturador suaument o usa l\'autotemporitzador.','Once you have a clearer photo, just email it to the same address as before — we\'ll pick it up automatically.'=>'Un cop tinguis una foto més clara, només has d\'enviar-la per correu a la mateixa adreça que abans — la recollirem automàticament.','Your previous submission is saved in your submissions page in case you want to review what was sent.'=>'La teva tramesa anterior està desada a la teva pàgina de trameses per si vols revisar què es va enviar.','View submissions →'=>'Veure les trameses →','Photo'=>'Foto','%s (original)'=>'%s (original)','%s (poster frame)'=>'%s (marc del pòster)','Failed to insert attachment.'=>'No s\'ha pogut inserir l\'adjunt.','Artwork or event not found.'=>'No s\'ha trobat l\'obra o l\'esdeveniment.','%s already removed.'=>'%s ja s\'ha eliminat.','Could not remove the %s. Please try again.'=>'No s\'ha pogut eliminar el %s. Si us plau, torna-ho a provar.','Your %s has been removed.'=>'S\'ha eliminat el teu %s.','A valid removal token is required.'=>'Cal un testimoni d\'eliminació vàlid.','No pending removal request found for this item.'=>'No s\'ha trobat cap sol·licitud d\'eliminació pendent per a aquest element.','The removal link has expired. Please send another removal request.'=>'L\'enllaç d\'eliminació ha caducat. Si us plau, envia una altra sol·licitud d\'eliminació.','Invalid removal token.'=>'Testimoni d\'eliminació invàlid.','View it live'=>'Veure-ho en directe','Biography published'=>'Biografia publicada','Your biography has been published.'=>'La teva biografia s\'ha publicat.','Event published'=>'Esdeveniment publicat','The event has been published.'=>'L\'esdeveniment s\'ha publicat.','Artwork published'=>'Obra publicada','The artwork has been published to the gallery.'=>'L’obra s’ha publicat a la galeria.','Submission discarded'=>'Enviament descartat','The submission has been discarded.'=>'L’enviament s’ha descartat.','Biography removed'=>'Biografia eliminada','Your biography has been removed.'=>'La teva biografia s’ha eliminat.','Event removed'=>'Esdeveniment eliminat','The event has been removed.'=>'L’esdeveniment s’ha eliminat.','Artwork removed'=>'Obra eliminada','Your artwork has been removed from the gallery.'=>'La teva obra s’ha eliminat de la galeria.','This link may have already been used or may have expired. Please log in to manage your submissions.'=>'És possible que aquest enllaç ja s’hagi fet servir o hagi caducat. Inicia sessió per gestionar els teus enviaments.','Title and full text cannot be empty. Fill them back in, or use "Discard" from the original email instead.'=>'El títol i el text complet no poden estar buits. Torna’ls a introduir, o fes servir «Descarta» des del correu electrònic original.','The full text cannot be empty. Fill it back in, or use "Discard" from the original email instead.'=>'El text complet no pot estar buit. Torna’l a introduir, o fes servir «Descarta» des del correu electrònic original.','Portfolio link'=>'Enllaç del portafoli','Social link %d (optional)'=>'Enllaç social %d (opcional)','Hour'=>'Hora','Location'=>'Ubicació','Address'=>'Adreça','Timezone'=>'Fus horari','Other'=>'Altres','— Not set —'=>'— No definit —','Discard this submission?'=>'Descartar aquest enviament?','This will permanently discard the submission — it will not be published.'=>'Això descartarà permanentment l’enviament; no es publicarà.','Yes, discard it'=>'Sí, descarta’l','Remove this artwork?'=>'Eliminar aquesta obra?','This will remove the published artwork from the gallery.'=>'Això eliminarà l’obra publicada de la galeria.','Yes, remove it'=>'Sí, elimina-la','Title'=>'Títol','Short description'=>'Breu descripció','Full text'=>'Text complet','Publish this %s?'=>'Publicar aquest %s?','Make any final changes below, or leave everything as-is to publish exactly what was drafted.'=>'Fes qualsevol canvi final a continuació, o deixa-ho tot tal com està per publicar exactament el que s’ha esbossat.','Publish it'=>'Publica-ho','biography'=>'biografia','Submission not found.'=>'No s’ha trobat l’enviament.','This submission is not awaiting review.'=>'Aquest enviament no està pendent de revisió.','The original published item could not be found.'=>'No s’ha pogut trobar l’element publicat original.','You do not have permission to review this submission.'=>'No tens permís per revisar aquest enviament.','Review link not found or already used.'=>'No s’ha trobat l’enllaç de revisió o ja s’ha fet servir.','Invalid review token.'=>'Testimoni de revisió no vàlid.','This review link has expired. Please log in to manage your submissions.'=>'Aquest enllaç de revisió ha caducat. Inicia sessió per gestionar els teus enviaments.','No submissions awaiting review.'=>'No hi ha enviaments pendents de revisió.','Make changes'=>'Fes canvis','One-line description'=>'Descripció d’una línia','Description'=>'Descripció','Tags (comma-separated)'=>'Etiquetes (separades per comes)','Save &amp; Publish'=>'Desa i publica','Publishing…'=>'S’està publicant…','Published ✓'=>'Publicat ✓','Something went wrong.'=>'Alguna cosa ha anat malament.','Could not connect. Please try again.'=>'No s’ha pogut connectar. Torna-ho a provar.','Discard this submission? This cannot be undone.'=>'Descartar aquest enviament? Això no es pot desfer.','Discarding…'=>'Descartant…','Discarded.'=>'Descartat.','Saving and publishing…'=>'Desant i publicant…','Log in to view your submissions'=>'Inicia sessió per veure les teves sol·licituds','Username or email address'=>'Nom d’usuari o adreça electrònica','Password'=>'Contrasenya','Log in'=>'Inicia sessió','Remember me'=>'Recorda’m','Forgot your password?'=>'Has oblidat la contrasenya?','Book'=>'Llibre','Person'=>'Persona','Calendar'=>'Calendari','Pin'=>'Pin','Baseline (default)'=>'Línia base (per defecte)','Top'=>'A dalt','Middle'=>'Centre','Bottom'=>'A baix','Icon settings'=>'Configuració de la icona','Biography icon'=>'Icona de biografia','Events icon'=>'Icona d’esdeveniments','Icon size'=>'Mida de la icona','Icon vertical align'=>'Alineació vertical de la icona','Icon-only links have no text baseline of their own — use this if they sit too high or low next to the artist name once Icon size is changed from the default.'=>'Els enllaços només amb icona no tenen una línia base de text pròpia — fes servir això si queden massa amunt o massa avall al costat del nom de l’artista un cop la mida de la icona s’ha canviat respecte al valor per defecte.','Icon color'=>'Color de la icona','Leave unset to match the block’s own text color.'=>'Deixa-ho sense definir perquè coincideixi amb el color del text del bloc.','Artist Name'=>'Nom de l’artista','Envelope'=>'Sobre','Speech bubble'=>'Bafarada','Contact'=>'Contacte','Link settings'=>'Configuració de l’enllaç','Link type'=>'Tipus d’enllaç','Icon'=>'Icona','Biography Icon'=>'Icona de biografia','Icon-only link to the artist’s biography.'=>'Enllaç només amb icona a la biografia de l’artista.','Events Icon'=>'Icona d’esdeveniments','Icon-only link to the artist’s events archive.'=>'Enllaç només amb icona a l’arxiu d’esdeveniments de l’artista.','Contact Icon'=>'Icona de contacte','Opens a popover with a form to message the artist directly. Hidden automatically if the artist has turned contact messages off.'=>'Obre un popover amb un formulari per enviar un missatge directament a l’artista. S’amaga automàticament si l’artista ha desactivat els missatges de contacte.','Artist Contact Form'=>'Formulari de contacte de l’artista','Lets a visitor message the current artist subdomain’s artist. Content is rendered live on the frontend, for the artist currently being viewed.'=>'Permet que una persona visitant enviï un missatge a l’artista del subdomini actual de l’artista. El contingut es renderitza en directe al frontend, per a l’artista que s’està visualitzant actualment.','Gallery settings'=>'Configuració de la galeria','Columns'=>'Columnes','✦ Agnosis Gallery Overview — rendered on the server'=>'✦ Resum de la galeria d’Agnosis — renderitzat al servidor','columns · proportional · random daily order'=>'columnes · proporcional · ordre diari aleatori','Join Agnosis'=>'Uneix-te a Agnosis','Public application form for new artists. Submits name, email, bio, portfolio URL and a personal statement to the community for review. Content is rendered live on the frontend.'=>'Formulari públic de sol·licitud per a nous artistes. Envia nom, correu electrònic, biografia, URL del portafolis i una declaració personal a la comunitat perquè la revisi. El contingut es renderitza en directe al frontend.','Place this block on your /join/ page or in a Site Editor page template assigned to that page.'=>'Col·loca aquest bloc a la teva pàgina /join/ o en una plantilla de Site Editor assignada a aquesta pàgina.','Bell'=>'Campana','Star'=>'Estrella','Lightning bolt'=>'Llamp','Newsletter Popover — opens the signup form'=>'Popover del butlletí — obre el formulari de registre','Newsletter settings'=>'Configuració del butlletí','Trigger icon'=>'Icona activadora','Pick something that won’t blend in with icons already sitting next to it (e.g. Social Share).'=>'Tria alguna cosa que no es barregi amb les icones que ja hi ha al costat (p. ex. Compartir a xarxes socials).','Newsletter Signup'=>'Registre al butlletí','Email signup form for the public newsletter. A confirmation email is sent before anyone is added to the send list (double opt-in). Content is rendered live on the frontend.'=>'Formulari de registre per correu electrònic per al butlletí públic. S\'envia un correu electrònic de confirmació abans que ningú sigui afegit a la llista d\'enviament (double opt-in). El contingut es renderitza en directe al frontal.','block titleArtist Breadcrumb'=>'Breadcrumb de l\'artista','block descriptionSmall line identifying the artist whose subdomain is currently being viewed. Renders nothing on the main Agnosis site.'=>'Petita línia que identifica l\'artista el subdomini del qual s\'està veient. No es mostra al lloc principal d\'Agnosis.','block keywordartist'=>'artista','block keywordbreadcrumb'=>'breadcrumb','block keywordsubdomain'=>'subdomini','block keywordagnosis'=>'agnosis','block titleArtist Name Link'=>'Enllaç al nom de l\'artista','block descriptionLinks to the current artist\'s own subdomain home. Renders nothing off an artist subdomain.'=>'Enllaça amb la pàgina principal del subdomini propi de l\'artista actual. No es mostra fora d\'un subdomini d\'artista.','block titleBreadcrumb Icon Link'=>'Enllaç d\'icona de breadcrumb','block descriptionA single icon-only link (Biography, Events, or a Contact popover) to/about the current artist. Renders nothing if there\'s nothing to show (no biography/events yet, or the artist has turned contact off), or off an artist subdomain.'=>'Un únic enllaç només amb icona (Biografia, Esdeveniments o un popover de Contacte) cap a/sobre l\'artista actual. No es mostra si no hi ha res a mostrar (encara no hi ha biografia/esdeveniments, o l\'artista ha desactivat el contacte), ni tampoc fora d\'un subdomini d\'artista.','block keywordbiography'=>'biografia','block keywordevents'=>'esdeveniments','block keywordcontact'=>'contacte','block keywordicon'=>'icona','block titleArtist Contact Form'=>'Formulari de contacte de l\'artista','block descriptionContact form letting a visitor message the current artist subdomain\'s artist. Submits to a per-artist REST endpoint; the message is moderated, translated into the artist\'s own language, and emailed to them.'=>'Formulari de contacte que permet a un visitant enviar un missatge a l\'artista del subdomini de l\'artista actual. S\'envia a un punt final REST per artista; el missatge es modera, es tradueix a la llengua pròpia de l\'artista i se li envia per correu electrònic.','block keywordmessage'=>'missatge','block keywordemail'=>'correu electrònic','block titleAgnosis Gallery Overview'=>'Visió general de la galeria d\'Agnosis','block descriptionProportional, randomized artwork grid across all artists. Shows featured artworks first, respects per-artist budget, supports medium filtering and pagination.'=>'Graella proporcional i aleatòria d\'obres d\'art de tots els artistes. Mostra primer les obres destacades, respecta el pressupost de cada artista, admet filtratge per mitjà i paginació.','block keywordgallery'=>'galeria','block keywordartwork'=>'obra d\'art','block keywordartists'=>'artistes','block keywordoverview'=>'visió general','block titleJoin Agnosis'=>'Uneix-te a Agnosis','block descriptionPublic application form for artists who want to join the Agnosis network. Submits to the admission REST endpoint. Place this on your /join/ page.'=>'Formulari públic de sol·licitud per a artistes que volen unir-se a la xarxa d\'Agnosis. S\'envia al punt final REST d\'admissió. Col·loca\'l a la teva pàgina /join/.','block keywordjoin'=>'unir-se','block keywordapply'=>'sol·licitar','block keywordapplication'=>'sol·licitud','block keywordadmission'=>'admissió','block titleNewsletter Popover'=>'Popover del butlletí','block descriptionIcon button that opens a full-viewport popover containing the newsletter signup form. Self-contained — drop it directly into a header or footer template part; renders nothing when the public newsletter is disabled (Settings → Newsletter).'=>'Botó amb icona que obre un popover a pantalla completa que conté el formulari de registre del butlletí. Autònom — afegeix-lo directament a una part de plantilla de capçalera o peu; no es mostra quan el butlletí públic està desactivat (Configuració → Butlletí).','block keywordnewsletter'=>'butlletí','block keywordsubscribe'=>'subscriure\'s','block keywordpopover'=>'popover','block keywordfooter'=>'peu de pàgina','block titleNewsletter Signup'=>'Registre al butlletí','block descriptionEmail signup form for the public newsletter (double opt-in). Submits to the newsletter subscribe REST endpoint.'=>'Formulari de registre per correu electrònic per al butlletí públic (double opt-in). S\'envia al punt final REST de subscripció al butlletí.','block keywordsignup'=>'registre','block titleMy Submissions'=>'Les meves trameses','block descriptionLists the logged-in artist\'s pending artwork submissions for review and approval. Place this on your /my-submissions/ page or in a Site Editor template.'=>'Mostra les trameses d\'obres pendents de revisió i aprovació de l\'artista amb sessió iniciada. Col·loca això a la teva pàgina /my-submissions/ o en una plantilla de Site Editor.','block keywordsubmissions'=>'trameses','block keywordreview'=>'revisió']];